const input = $input.first()?.json ?? {};

const OPENAI_DEFAULT_MODEL = 'cx/gpt-5.4';
const OPENAI_FALLBACK_MODEL = 'cx/gpt-5.2';

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function normalizeText(value) {
  return String(value ?? '').replace(/\r\n/g, '\n').trim();
}

function asInt(value, fallback = 0, min = 0, max = 1000000) {
  const number = Number(value);
  const normalized = Number.isFinite(number) ? Math.floor(number) : fallback;
  return Math.min(max, Math.max(min, normalized));
}

function normalizeModelName(rawValue, defaultValue = OPENAI_DEFAULT_MODEL) {
  const fallback = safeText(defaultValue) || OPENAI_DEFAULT_MODEL;
  const raw = safeText(rawValue);
  if (!raw) return fallback;

  const lowerRaw = raw.toLowerCase();
  if (lowerRaw === 'gpt-5') return OPENAI_DEFAULT_MODEL;

  if (/^cx\//i.test(raw) || /^gemini-/i.test(raw) || /^nano-banana/i.test(raw)) {
    return raw;
  }

  if (/^gpt-[a-z0-9.\-]+$/i.test(raw)) {
    return 'cx/' + raw;
  }

  return raw;
}

function safeJsonParse(value, fallback = null) {
  try {
    return JSON.parse(String(value ?? ''));
  } catch (_) {
    return fallback;
  }
}

function parseJsonObject(rawText) {
  const raw = safeText(rawText);
  if (!raw) return null;

  const direct = safeJsonParse(raw, null);
  if (direct && typeof direct === 'object') {
    return direct;
  }

  const fence = raw.match(/\x60\x60\x60(?:json)?\s*([\s\S]*?)\x60\x60\x60/i);
  if (fence) {
    const parsedFence = safeJsonParse(fence[1], null);
    if (parsedFence && typeof parsedFence === 'object') {
      return parsedFence;
    }
  }

  const firstObj = raw.indexOf('{');
  const lastObj = raw.lastIndexOf('}');
  if (firstObj >= 0 && lastObj > firstObj) {
    const parsedObj = safeJsonParse(raw.slice(firstObj, lastObj + 1), null);
    if (parsedObj && typeof parsedObj === 'object') {
      return parsedObj;
    }
  }

  return null;
}

function normalizeList(value) {
  if (Array.isArray(value)) {
    return value.map((item) => safeText(item)).filter(Boolean);
  }

  if (typeof value === 'string') {
    return value
      .split(/[\n,|]+/)
      .map((item) => item.trim())
      .filter(Boolean);
  }

  return [];
}

function normalizeStyleKeywords(value) {
  const base = normalizeList(value);
  const dedupe = [];
  for (const item of base) {
    if (!dedupe.includes(item)) dedupe.push(item);
  }
  return dedupe.slice(0, 8);
}

function parseBookInfo(userInput, explicitTitle, explicitAuthor) {
  const titleFromInput = safeText(explicitTitle);
  const authorFromInput = safeText(explicitAuthor);
  if (titleFromInput || authorFromInput) {
    return {
      title: titleFromInput || safeText(userInput, 'Sách chưa rõ tên'),
      author: authorFromInput,
    };
  }

  const text = safeText(userInput);
  const byAuthorPattern = text.match(/^(.*?)(?:\s+(?:của|cua)\s+t[aá]c\s+gi[aả]\s+)(.+)$/i);
  if (byAuthorPattern) {
    return {
      title: safeText(byAuthorPattern[1], text),
      author: safeText(byAuthorPattern[2]),
    };
  }

  return {
    title: text || 'Sách chưa rõ tên',
    author: '',
  };
}

function normalizeOutline(rawOutline) {
  const source = rawOutline && typeof rawOutline === 'object' ? rawOutline : {};
  const rawScenes = Array.isArray(source.scenes) ? source.scenes : [];

  let sceneCount = asInt(source.scene_count, 0, 0, 100);
  if (sceneCount < 8 || sceneCount > 14) {
    const byScenes = asInt(rawScenes.length, 0, 0, 100);
    sceneCount = byScenes >= 8 && byScenes <= 14 ? byScenes : 10;
  }

  const scenes = [];
  for (let i = 0; i < sceneCount; i += 1) {
    const sourceItem = rawScenes[i] && typeof rawScenes[i] === 'object' ? rawScenes[i] : {};
    const order = i + 1;

    let role = safeText(sourceItem.scene_role).toLowerCase();
    if (order === 1) role = 'hook';
    else if (order === sceneCount) role = 'outro';
    else if (role !== 'core') role = 'core';

    scenes.push({
      order,
      scene_role: role,
      scene_goal: safeText(sourceItem.scene_goal, role === 'hook'
        ? 'Mở đầu gây tò mò bằng một nghịch lý hoặc câu hỏi lớn.'
        : role === 'outro'
          ? 'Kết đọng lại thông điệp chính và lời kêu gọi hành động nhẹ.'
          : 'Phát triển một luận điểm cốt lõi của cuốn sách.'),
      key_points: normalizeList(sourceItem.key_points).slice(0, 6),
    });
  }

  const estimated = asInt(source.estimated_total_duration_sec, 0, 0, 20000);
  const estimatedTotalDurationSec = estimated > 0
    ? estimated
    : scenes.reduce((acc, scene) => acc + (scene.scene_role === 'core' ? 95 : 60), 0);

  return {
    angle: safeText(source.angle, 'Review theo hướng giải mã tư tưởng cốt lõi và ứng dụng thực tế.'),
    target_audience: safeText(source.target_audience, 'Khán giả muốn hiểu sâu nhưng dễ áp dụng.'),
    scene_count: sceneCount,
    estimated_total_duration_sec: estimatedTotalDurationSec,
    scenes,
  };
}

function normalizeManifest(rawManifest, context) {
  const source = rawManifest && typeof rawManifest === 'object' ? rawManifest : {};
  const targetSceneCount = asInt(context?.target_scene_count, 10, 8, 14);
  const sourceScenes = Array.isArray(source.scenes) ? source.scenes : [];

  const scenes = [];
  for (let i = 0; i < targetSceneCount; i += 1) {
    const sourceScene = sourceScenes[i] && typeof sourceScenes[i] === 'object' ? sourceScenes[i] : {};
    const order = i + 1;
    const sceneId = 'scene_' + String(order).padStart(2, '0');

    let sceneRole = safeText(sourceScene.scene_role).toLowerCase();
    if (order === 1) sceneRole = 'hook';
    else if (order === targetSceneCount) sceneRole = 'outro';
    else if (sceneRole !== 'core') sceneRole = 'core';

    const narrationText = normalizeText(sourceScene.narration_text);
    const fallbackNarration = sceneRole === 'hook'
      ? 'Nếu một ý tưởng có thể thay đổi cả cách ta nhìn cuộc sống, liệu bạn có dám bắt đầu lại từ trang đầu tiên?'
      : sceneRole === 'outro'
        ? 'Điều quan trọng không phải đọc xong cuốn sách, mà là chọn một hành động nhỏ ngay hôm nay để sống khác đi.'
        : 'Phân cảnh này đi sâu vào một luận điểm quan trọng của cuốn sách và cách áp dụng nó vào đời sống thực tế.';

    let duration = asInt(sourceScene.estimated_duration_sec, 0, 0, 500);
    if (duration <= 0) {
      duration = sceneRole === 'core' ? 95 : 60;
    }

    scenes.push({
      scene_id: sceneId,
      order,
      scene_title: safeText(sourceScene.scene_title, sceneRole === 'hook'
        ? 'Mở Hook'
        : sceneRole === 'outro'
          ? 'Kết Đọng'
          : 'Phân Cảnh ' + String(order).padStart(2, '0')),
      scene_role: sceneRole,
      narration_text: narrationText || fallbackNarration,
      image_prompt_en: safeText(sourceScene.image_prompt_en, 'cinematic storytelling illustration, warm light, emotional depth, highly detailed'),
      highlight_quote_vi: safeText(sourceScene.highlight_quote_vi),
      estimated_duration_sec: duration,
      transition: safeText(sourceScene.transition, 'cut'),
    });
  }

  const estimatedTotal = asInt(
    source?.video?.estimated_total_duration_sec,
    scenes.reduce((sum, scene) => sum + asInt(scene.estimated_duration_sec, 0, 0, 500), 0),
    0,
    20000,
  );

  const styleKeywords = normalizeStyleKeywords(
    source?.book?.style_keywords && Array.isArray(source.book.style_keywords)
      ? source.book.style_keywords
      : context?.style_keywords,
  );

  return {
    book: {
      title: safeText(source?.book?.title, safeText(context?.book?.title, 'Sách chưa rõ tên')),
      author: safeText(source?.book?.author, safeText(context?.book?.author)),
      style_keywords: styleKeywords,
    },
    video: {
      aspect_ratio: '16:9',
      target_duration_min_sec: 900,
      target_duration_max_sec: 1200,
      estimated_total_duration_sec: estimatedTotal,
    },
    scenes,
  };
}

function buildReadableDraft(manifest) {
  const scenes = Array.isArray(manifest?.scenes) ? manifest.scenes : [];
  const blocks = [];

  for (const scene of scenes) {
    const title = safeText(scene.scene_title, scene.scene_id);
    const role = safeText(scene.scene_role);
    const narration = normalizeText(scene.narration_text);
    const quote = safeText(scene.highlight_quote_vi);

    const lines = [];
    lines.push('## ' + safeText(scene.scene_id, 'scene') + ' - ' + title + ' (' + role + ')');
    if (narration) lines.push(narration);
    if (quote) lines.push('Quote: "' + quote + '"');

    blocks.push(lines.join('\n'));
  }

  return blocks.join('\n\n').trim();
}

function countTotalChars(manifest) {
  const scenes = Array.isArray(manifest?.scenes) ? manifest.scenes : [];
  return scenes.reduce((sum, scene) => sum + String(scene?.narration_text ?? '').length, 0);
}

function buildSectionCompat(manifest) {
  const scenes = Array.isArray(manifest?.scenes) ? manifest.scenes : [];
  return scenes.map((scene) => ({
    order: asInt(scene.order, 1, 1, 100),
    id: safeText(scene.scene_id, 'scene_' + String(asInt(scene.order, 1, 1, 100)).padStart(2, '0')),
    title: safeText(scene.scene_title),
    content: normalizeText(scene.narration_text),
    file_name: String(asInt(scene.order, 1, 1, 100)).padStart(2, '0') + '_' + safeText(scene.scene_id, 'scene').toLowerCase() + '.txt',
  }));
}

function createSessionToken() {
  return Date.now().toString(36) + Math.random().toString(36).slice(2, 10);
}

const requestHelper =
  helpers?.httpRequest ??
  (typeof $helpers !== 'undefined' ? $helpers?.httpRequest : undefined);

const proxyBaseUrl = safeText(input.proxy_base_url).replace(/\/$/, '');
const proxyApiKey = safeText(input.proxy_api_key);
const userInput = safeText(input.user_input);
const outlinePromptTemplate = safeText(input.scene_outline_prompt_template, safeText(input.master_prompt_template));
const expandPromptTemplate = safeText(input.scene_expand_prompt_template, safeText(input.master_prompt_template));
const primaryModel = normalizeModelName(input.content_model, OPENAI_DEFAULT_MODEL);
const fallbackModel = normalizeModelName(input.fallback_model, OPENAI_FALLBACK_MODEL);
const qcModel = normalizeModelName(input.qc_model, OPENAI_DEFAULT_MODEL);
const reviewerWaitTimeoutSeconds = asInt(input.reviewer_wait_timeout_seconds, 900, 60, 7200);
const qcScoreWarningThreshold = asInt(input.qc_score_warning_threshold, 7, 0, 10);

const telegramBotToken = safeText(input.telegram_bot_token);
const telegramChatId = safeText(input.chat_id ?? input.telegram_chat_id ?? input.message?.chat?.id);
const startSource = safeText(input.start_source);

function baseOutput(overrides = {}) {
  return {
    ...input,
    message: '',
    full_review: '',
    review_readable: '',
    review_manifest: null,
    review_sections: [],
    review_sections_count: 0,
    turn_count: 0,
    stop_reason: 'completed',
    content_model: primaryModel,
    fallback_model: fallbackModel || null,
    fallback_used: false,
    user_input: userInput,
    proxy_base_url: proxyBaseUrl,
    proxy_api_key: proxyApiKey,
    qc_model: qcModel,
    qc_score_warning_threshold: qcScoreWarningThreshold,
    reviewer_wait_timeout_seconds: reviewerWaitTimeoutSeconds,
    ...overrides,
  };
}

if (!userInput) {
  return [{
    json: baseOutput({
      message: 'Vui lòng nhập tên sách và tác giả trong chat. Ví dụ: Sách Nhà Giả Kim của tác giả Paulo Coelho.',
      stop_reason: 'missing_input',
    }),
  }];
}

if (!proxyBaseUrl || !proxyApiKey) {
  return [{
    json: baseOutput({
      message: 'Thiếu cấu hình proxy (base URL hoặc client key).',
      stop_reason: 'api_error',
    }),
  }];
}

if (!outlinePromptTemplate || !expandPromptTemplate) {
  return [{
    json: baseOutput({
      message: 'Thiếu prompt scene-outline hoặc scene-expand trong Set Config.',
      stop_reason: 'api_error',
    }),
  }];
}

if (typeof requestHelper !== 'function') {
  return [{
    json: baseOutput({
      message: 'Thiếu helper HTTP trong Code node runtime (cần helpers.httpRequest).',
      stop_reason: 'api_error',
    }),
  }];
}

async function telegramApi(method, body, allowError = false) {
  if (!telegramBotToken || !telegramChatId) {
    return null;
  }

  try {
    return await requestHelper({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + telegramBotToken + '/' + method,
      body,
      json: true,
      timeout: 20000,
    });
  } catch (error) {
    if (allowError) return null;
    throw error;
  }
}

async function sendProgress(text) {
  if (startSource !== 'telegram_command') return null;
  const response = await telegramApi('sendMessage', {
    chat_id: telegramChatId,
    text: safeText(text, 'Dang xu ly...'),
  }, true);
  const id = Number(response?.result?.message_id ?? NaN);
  return Number.isFinite(id) && id > 0 ? Math.floor(id) : null;
}

async function editProgress(messageId, text) {
  const id = Number(messageId);
  if (!Number.isFinite(id) || id <= 0) return;
  await telegramApi('editMessageText', {
    chat_id: telegramChatId,
    message_id: id,
    text: safeText(text, 'Dang xu ly...'),
    disable_web_page_preview: true,
  }, true);
}

async function deleteProgress(messageId) {
  const id = Number(messageId);
  if (!Number.isFinite(id) || id <= 0) return;
  await telegramApi('deleteMessage', {
    chat_id: telegramChatId,
    message_id: id,
  }, true);
}

function shouldTryFallback(errorText) {
  return /429|RESOURCE_EXHAUSTED|MODEL_CAPACITY_EXHAUSTED|No capacity available|cooling down/i.test(String(errorText ?? ''));
}

async function callOpenAiJson(systemPrompt, userPayload, options = {}) {
  const candidateModels = [safeText(options.model, primaryModel)];
  const normalizedFallback = safeText(options.fallbackModel, fallbackModel);
  if (normalizedFallback && normalizedFallback !== candidateModels[0]) {
    candidateModels.push(normalizedFallback);
  }

  let lastError = null;

  for (let i = 0; i < candidateModels.length; i += 1) {
    const model = candidateModels[i];
    try {
      const response = await requestHelper({
        method: 'POST',
        url: proxyBaseUrl + '/v1/chat/completions',
        headers: {
          Authorization: 'Bearer ' + proxyApiKey,
        },
        body: {
          model,
          messages: [
            {
              role: 'system',
              content: String(systemPrompt ?? ''),
            },
            {
              role: 'user',
              content: JSON.stringify(userPayload),
            },
          ],
          response_format: { type: 'json_object' },
          stream: false,
        },
        json: true,
        timeout: 300000,
      });

      const content = safeText(response?.choices?.[0]?.message?.content);
      const parsed = parseJsonObject(content);
      if (!parsed || typeof parsed !== 'object') {
        throw new Error('Model returned non-JSON content.');
      }

      return {
        model,
        parsed,
      };
    } catch (error) {
      lastError = error;
      const message = error?.message ? String(error.message) : String(error);
      const canContinue = i + 1 < candidateModels.length && shouldTryFallback(message);
      if (!canContinue) {
        throw error;
      }
    }
  }

  throw lastError ?? new Error('Unknown model call error.');
}

const sessionToken = safeText(input.session_token, createSessionToken());
const source = safeText(input.source, 'main');
const instruction = safeText(input.instruction);
const eventType = safeText(input.event_type, 'init_review');
const styleKeywords = normalizeStyleKeywords(input.style_keywords ?? input.review_style_keywords ?? input.style);
const book = parseBookInfo(userInput, input.book_title, input.book_author);

let progressMessageId = null;
let outlineModelUsed = primaryModel;
let expandModelUsed = primaryModel;
let fallbackUsed = false;
let stopReason = 'completed';
let errorMessage = '';
let outline = null;
let manifest = null;

try {
  progressMessageId = await sendProgress('Dang phan tich sach va tao scene outline...');

  const outlinePayload = {
    book_request: userInput,
    book,
    style_keywords: styleKeywords,
    constraints: {
      scene_count_min: 8,
      scene_count_max: 14,
      fallback_scene_count: 10,
      target_duration_min_sec: 900,
      target_duration_max_sec: 1200,
      target_chars_min: 15000,
      target_chars_max: 20000,
    },
  };

  const outlineResponse = await callOpenAiJson(outlinePromptTemplate, outlinePayload, {
    model: primaryModel,
    fallbackModel,
  });
  outlineModelUsed = safeText(outlineResponse.model, primaryModel);
  outline = normalizeOutline(outlineResponse.parsed);
  fallbackUsed = fallbackUsed || outlineModelUsed !== primaryModel;

  await editProgress(progressMessageId, 'Dang mo rong noi dung tung scene...');

  const expandPayload = {
    book_request: userInput,
    book,
    style_keywords: styleKeywords,
    outline,
    constraints: {
      scene_count: outline.scene_count,
      target_duration_min_sec: 900,
      target_duration_max_sec: 1200,
      target_chars_min: 15000,
      target_chars_max: 20000,
      hook_and_outro_duration_sec: '45-75',
      core_duration_sec: '75-120',
      core_min_duration_sec: 45,
      aspect_ratio: '16:9',
    },
  };

  const expandResponse = await callOpenAiJson(expandPromptTemplate, expandPayload, {
    model: primaryModel,
    fallbackModel,
  });
  expandModelUsed = safeText(expandResponse.model, primaryModel);
  fallbackUsed = fallbackUsed || expandModelUsed !== primaryModel;

  manifest = normalizeManifest(expandResponse.parsed, {
    book,
    style_keywords: styleKeywords,
    target_scene_count: outline.scene_count,
  });
} catch (error) {
  stopReason = 'api_error';
  errorMessage = error?.message ? String(error.message) : String(error);
} finally {
  if (progressMessageId) {
    await deleteProgress(progressMessageId);
  }
}

if (stopReason === 'api_error' || !manifest) {
  return [{
    json: baseOutput({
      message: 'Loi tao scene manifest: ' + (errorMessage || 'unknown_error'),
      stop_reason: stopReason,
      turn_count: 2,
      content_model: expandModelUsed || outlineModelUsed || primaryModel,
      fallback_used: fallbackUsed,
      start_progress_message_id: progressMessageId,
      session_token: sessionToken,
      source,
      instruction,
      event_type: eventType,
    }),
  }];
}

const reviewReadable = buildReadableDraft(manifest);
const totalChars = countTotalChars(manifest);
const reviewSections = buildSectionCompat(manifest);
const introScene = manifest.scenes.find((scene) => safeText(scene.scene_role) === 'hook') ?? manifest.scenes[0] ?? null;
const outroScene = [...manifest.scenes].reverse().find((scene) => safeText(scene.scene_role) === 'outro') ?? manifest.scenes[manifest.scenes.length - 1] ?? null;

const warnings = [];
if (manifest.scenes.length < 8 || manifest.scenes.length > 14) {
  warnings.push('scene_count_out_of_range');
}
if (totalChars < 15000 || totalChars > 20000) {
  warnings.push('total_chars_out_of_target');
}

return [{
  json: baseOutput({
    message: reviewReadable,
    full_review: reviewReadable,
    review_readable: reviewReadable,
    review_manifest: manifest,
    review_manifest_json: JSON.stringify(manifest, null, 2),
    review_sections: reviewSections,
    review_sections_count: reviewSections.length,
    review_intro: safeText(introScene?.narration_text),
    review_outro: safeText(outroScene?.narration_text),
    review_parse_status: 'parsed_scene_manifest',
    review_parser_warning: warnings.length > 0 ? warnings.join(',') : null,
    review_char_count: totalChars,
    review_scene_count: manifest.scenes.length,
    turn_count: 2,
    stop_reason: stopReason,
    content_model: expandModelUsed || outlineModelUsed || primaryModel,
    fallback_used: fallbackUsed,
    outline_model_used: outlineModelUsed,
    expand_model_used: expandModelUsed,
    scene_outline: outline,
    video_estimated_total_duration_sec: asInt(manifest.video?.estimated_total_duration_sec, 0, 0, 20000),
    metadata: input.metadata && typeof input.metadata === 'object' ? input.metadata : null,
    session_token: sessionToken,
    source,
    instruction,
    event_type: eventType,
    start_progress_message_id: progressMessageId,
  }),
}];

const input = $json ?? {};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function normalizeText(value) {
  return String(value ?? '').replace(/\r\n/g, '\n').trim();
}

function asInt(value, fallback = 0, min = 0, max = 1000000) {
  const number = Number(value);
  const normalized = Number.isFinite(number) ? Math.floor(number) : fallback;
  return Math.min(max, Math.max(min, normalized));
}

function safeJsonParse(value, fallback = null) {
  try {
    return JSON.parse(String(value ?? ''));
  } catch (_) {
    return fallback;
  }
}

function parseJsonObject(rawText) {
  const raw = safeText(rawText);
  if (!raw) return null;

  const direct = safeJsonParse(raw, null);
  if (direct && typeof direct === 'object') return direct;

  const fence = raw.match(/\x60\x60\x60(?:json)?\s*([\s\S]*?)\x60\x60\x60/i);
  if (fence) {
    const parsedFence = safeJsonParse(fence[1], null);
    if (parsedFence && typeof parsedFence === 'object') return parsedFence;
  }

  const firstObj = raw.indexOf('{');
  const lastObj = raw.lastIndexOf('}');
  if (firstObj >= 0 && lastObj > firstObj) {
    const parsedObj = safeJsonParse(raw.slice(firstObj, lastObj + 1), null);
    if (parsedObj && typeof parsedObj === 'object') return parsedObj;
  }

  return null;
}

function normalizeList(value) {
  if (Array.isArray(value)) {
    return value.map((item) => safeText(item)).filter(Boolean);
  }
  if (typeof value === 'string') {
    return value.split(/[\n,|]+/).map((item) => item.trim()).filter(Boolean);
  }
  return [];
}

function normalizeHashtags(value) {
  const base = normalizeList(value)
    .map((item) => item.replace(/^#+/, '').replace(/\s+/g, ''))
    .filter(Boolean)
    .map((item) => '#' + item.toLowerCase());

  const dedupe = [];
  for (const tag of base) {
    if (!dedupe.includes(tag)) dedupe.push(tag);
  }

  return dedupe.slice(0, 15);
}

function normalizeMetadata(metadataInput) {
  const source = metadataInput && typeof metadataInput === 'object' ? metadataInput : {};
  const hashtags = normalizeHashtags(source.hashtags);
  return {
    title: safeText(source.title),
    caption: safeText(source.caption),
    thumbnail_text: safeText(source.thumbnail_text),
    hashtags,
  };
}

function normalizeScene(scene, index) {
  const source = scene && typeof scene === 'object' ? scene : {};
  const order = asInt(source.order, index + 1, 1, 100);
  const sceneId = safeText(source.scene_id, 'scene_' + String(order).padStart(2, '0'));

  let role = safeText(source.scene_role).toLowerCase();
  if (order === 1) role = 'hook';
  else if (role !== 'outro' && role !== 'core' && role !== 'hook') role = 'core';

  return {
    scene_id: sceneId,
    order,
    scene_title: safeText(source.scene_title, 'Phân Cảnh ' + String(order).padStart(2, '0')),
    scene_role: role,
    narration_text: normalizeText(source.narration_text),
    image_prompt_en: safeText(source.image_prompt_en, 'cinematic storytelling illustration, warm light, emotional depth'),
    highlight_quote_vi: safeText(source.highlight_quote_vi),
    estimated_duration_sec: asInt(source.estimated_duration_sec, role === 'core' ? 95 : 60, 15, 300),
    transition: safeText(source.transition, 'cut'),
  };
}

function normalizeManifest(rawManifest) {
  const source = rawManifest && typeof rawManifest === 'object' ? rawManifest : {};
  const scenesRaw = Array.isArray(source.scenes) ? source.scenes : [];

  let scenes = scenesRaw.map((scene, idx) => normalizeScene(scene, idx));

  if (scenes.length === 0) {
    const fallbackText = normalizeText(input.review_readable ?? input.full_review ?? input.message);
    if (fallbackText) {
      scenes = [{
        scene_id: 'scene_01',
        order: 1,
        scene_title: 'Nội Dung Review',
        scene_role: 'core',
        narration_text: fallbackText,
        image_prompt_en: 'cinematic storytelling illustration, warm light, emotional depth',
        highlight_quote_vi: '',
        estimated_duration_sec: 120,
        transition: 'cut',
      }];
    }
  }

  if (scenes.length > 1) {
    scenes = scenes.map((scene, idx) => {
      if (idx === 0) {
        return { ...scene, scene_role: 'hook' };
      }
      if (idx === scenes.length - 1) {
        return { ...scene, scene_role: 'outro' };
      }
      return { ...scene, scene_role: 'core' };
    });
  }

  const estimatedTotalDurationSec = asInt(
    source?.video?.estimated_total_duration_sec,
    scenes.reduce((sum, scene) => sum + asInt(scene.estimated_duration_sec, 0, 0, 500), 0),
    0,
    20000,
  );

  return {
    book: {
      title: safeText(source?.book?.title, safeText(input.book_title)),
      author: safeText(source?.book?.author, safeText(input.book_author)),
      style_keywords: normalizeList(source?.book?.style_keywords).slice(0, 8),
    },
    video: {
      aspect_ratio: '16:9',
      target_duration_min_sec: 900,
      target_duration_max_sec: 1200,
      estimated_total_duration_sec: estimatedTotalDurationSec,
    },
    scenes,
  };
}

function buildReadable(manifest) {
  const scenes = Array.isArray(manifest?.scenes) ? manifest.scenes : [];
  const blocks = [];
  for (const scene of scenes) {
    const lines = [];
    lines.push('## ' + safeText(scene.scene_id) + ' - ' + safeText(scene.scene_title) + ' (' + safeText(scene.scene_role) + ')');
    lines.push(normalizeText(scene.narration_text));
    const quote = safeText(scene.highlight_quote_vi);
    if (quote) {
      lines.push('Quote: "' + quote + '"');
    }
    blocks.push(lines.join('\n'));
  }
  return blocks.join('\n\n').trim();
}

function buildSectionsCompat(manifest) {
  const scenes = Array.isArray(manifest?.scenes) ? manifest.scenes : [];
