  if (action === 'stop') return 'media_stop';
  return '';
}

function callbackEventType(stageCode, actionCode) {
  const stage =
    stageCode === 'media' ? 'media_pending' :
    stageCode === 'meta' ? 'metadata_pending' :
    'review_pending';

  const action =
    actionCode === 'c' ? 'continue' :
