function parseJsonObject(rawText) {
  const raw = String(rawText ?? '').trim();
  if (!raw) return null;

  try {
    return JSON.parse(raw);
  } catch (_) {}

  const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fence) {
    try {
      return JSON.parse(fence[1]);
    } catch (_) {}
  }

  const first = raw.indexOf('{');
  const last = raw.lastIndexOf('}');
  if (first >= 0 && last > first) {
    try {
      return JSON.parse(raw.slice(first, last + 1));
    } catch (_) {}
  }

  return null;
}

function normalizeList(value) {
  if (Array.isArray(value)) {
    return value.map((item) => String(item ?? '').trim()).filter(Boolean);
  }

  if (typeof value === 'string') {
    return value
      .split(/[\n,]+/)
      .map((item) => item.trim())
      .filter(Boolean);
  }

  return [];
}

function normalizeHashtags(value) {
  const tags = normalizeList(value)
    .map((item) => item.replace(/^#*/, '').replace(/\s+/g, ''))
    .filter(Boolean)
    .map((item) => '#' + item.toLowerCase());

  const unique = [];
  for (const tag of tags) {
    if (!unique.includes(tag)) {
      unique.push(tag);
    }
  }

  return unique.slice(0, 15);
}

function stripControlTags(text) {
  const normalized = String(text ?? '').replace(/\r\n/g, '\n').trim();
  return normalized.replace(/(?:\n|^)\s*-\s*(CONTINUE|END)\s*-\s*$/i, '').trim();
}

function normalizeReviewForDisplay(reviewText) {
  const normalized = stripControlTags(reviewText);
  const sectionRegex = /<<<SECTION\|([^|\n>]+)(?:\|([^\n>]+))?>>>\s*([\s\S]*?)\s*<<<END_SECTION>>>/g;
  const blocks = [];
  let match;

  while ((match = sectionRegex.exec(normalized)) !== null) {
    const title = safeText(match[2]);
    const content = safeText(match[3]);
    if (!content) continue;
    blocks.push(title ? (title + '\n' + content) : content);
  }

  if (blocks.length > 0) {
    return blocks.join('\n\n').trim();
  }

  return normalized
    .replace(/<<<SECTION\|[^>]+>>>/g, '')
    .replace(/<<<END_SECTION>>>/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function extractSectionText(review, id) {
  const regex = new RegExp('<<<SECTION\\|' + id + '(?:\\|[^>]+)?>>>\\s*([\\s\\S]*?)\\s*<<<END_SECTION>>>', 'i');
  const match = String(review ?? '').match(regex);
  return match ? String(match[1] ?? '').trim() : '';
}

function ensureKeepOthersInstruction(instruction) {
  const base = safeText(instruction);
  if (!base) return '';

  const keepPattern = /những\s+thứ\s+khác\s+giữ\s+nguyên|nhung\s+thu\s+khac\s+giu\s+nguyen|keep\s+(the\s+)?other\s+fields\s+unchanged/i;
  if (keepPattern.test(base)) {
    return base;
  }

  return base + '. Những thứ khác giữ nguyên.';
}

function detectMetadataTargets(instruction) {
  const text = String(instruction ?? '').toLowerCase();
  const targets = new Set();

  if (!text) {
    return targets;
  }

  if (/(\btitle\b|ti[eê]u\s*đ[eề]\b|tieu\s*de\b)/i.test(text)) {
    targets.add('title');
  }

  if (/(\bcaption\b|ch[uú]\s*th[ií]ch|m[oô]\s*t[aả]\s*ng[aă]n)/i.test(text)) {
    targets.add('caption');
  }

  if (/(\bthumbnail\b|\bthumb\b|thumbnail\s*text|anh\s*bia|ảnh\s*bìa)/i.test(text)) {
    targets.add('thumbnail_text');
  }

  if (/(\bhashtag\b|hash\s*tag|\btags?\b)/i.test(text)) {
    targets.add('hashtags');
  }

  return targets;
}

function isMetadataPlaceholderValue(value) {
  const normalized = safeText(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/đ/gi, 'd')
    .toLowerCase();

  if (normalized === 'tieu de video' || normalized === 'caption video' || normalized === 'thumbnail text') {
    return true;
  }

  // Legacy generic fallback strings from old workflow versions.
  if (normalized.includes('review sach') && normalized.includes('goc nhin dang suy ngam')) {
    return true;
  }
  if (normalized === 'doc de tham') {
    return true;
  }
  if (normalized.includes('cung minh boc tach y chinh cua cuon sach va cach ap dung vao doi song')) {
    return true;
  }

  return false;
}

function isMetadataPlaceholderBundle(metadata) {
  if (!metadata || typeof metadata !== 'object') {
    return true;
  }

  return isMetadataPlaceholderValue(metadata.title)
    || isMetadataPlaceholderValue(metadata.caption)
    || isMetadataPlaceholderValue(metadata.thumbnail_text);
}

function toAsciiSlug(value, fallback = '') {
  const normalized = safeText(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/đ/gi, 'd')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');

  return normalized || safeText(fallback);
}

function extractBookAndAuthorHints(text) {
  const raw = safeText(text);
  if (!raw) {
    return { title: '', author: '' };
  }

  const pattern = raw.match(/^(.*?)(?:\s+(?:cua|của)\s+t[aá]c\s+gi[aả]\s+)(.+)$/i);
  if (pattern) {
    return {
      title: safeText(pattern[1]).slice(0, 120),
      author: safeText(pattern[2]).slice(0, 120),
    };
  }

  return {
    title: raw.slice(0, 120),
    author: '',
  };
}

function buildMetadataFallbackTags(previousHashtags, contextInput) {
  const tags = [];
  const pushTag = (value) => {
    const normalized = safeText(value).replace(/^#*/, '').toLowerCase();
    if (!normalized) return;
    const tag = '#' + normalized;
    if (!tags.includes(tag)) {
      tags.push(tag);
    }
  };

  for (const tag of previousHashtags) {
    pushTag(tag);
  }

  const context = contextInput && typeof contextInput === 'object' ? contextInput : {};
  const hints = extractBookAndAuthorHints(context.user_input);

  pushTag('bookreview');
  pushTag('reviewsach');
  pushTag('phattrienbanthan');
  if (hints.title) {
    pushTag(toAsciiSlug(hints.title));
  }
  if (hints.author) {
    pushTag(toAsciiSlug(hints.author));
  }

  return tags.slice(0, 7);
}

function defaultMetadataFallback(previousMetadata, contextInput = null) {
  const previous = previousMetadata && typeof previousMetadata === 'object' ? previousMetadata : {};
  const previousHashtags = normalizeHashtags(previous.hashtags);
  const context = contextInput && typeof contextInput === 'object' ? contextInput : {};
  const hints = extractBookAndAuthorHints(context.user_input);

  const title = safeText(previous.title);
  const caption = safeText(previous.caption);
  const thumbnailText = safeText(previous.thumbnail_text);

  return {
    title: title && !isMetadataPlaceholderValue(title)
      ? title
      : hints.title
        ? 'Bạn đang sống hay chỉ đang chịu đựng? Câu trả lời từ "' + hints.title + '"'
        : 'Bạn đang sống hay chỉ đang chịu đựng mỗi ngày?',
    caption: caption && !isMetadataPlaceholderValue(caption)
      ? caption
      : 'Nếu bạn thấy mình cố gắng rất nhiều nhưng vẫn mắc kẹt, video này sẽ cùng bạn tìm ra gốc rễ và một bước đi nhỏ có thể làm ngay hôm nay.',
    thumbnail_text: thumbnailText && !isMetadataPlaceholderValue(thumbnailText)
      ? thumbnailText
      : 'Dừng lại 1 phút',
    hashtags: buildMetadataFallbackTags(previousHashtags, context),
  };
}

function normalizeMetadataBundle(metadataInput, fallbackInput = null, contextInput = null) {
  const fallback = defaultMetadataFallback(fallbackInput, contextInput);
  const source = metadataInput && typeof metadataInput === 'object'
    ? metadataInput
    : {};

  const hashtags = normalizeHashtags(source.hashtags);
  const resolvedTitle = safeText(source.title, fallback.title);
  const resolvedCaption = safeText(source.caption, fallback.caption);
  const resolvedThumbnail = safeText(source.thumbnail_text, fallback.thumbnail_text);

  return {
    title: isMetadataPlaceholderValue(resolvedTitle) ? fallback.title : resolvedTitle,
    caption: isMetadataPlaceholderValue(resolvedCaption) ? fallback.caption : resolvedCaption,
    thumbnail_text: isMetadataPlaceholderValue(resolvedThumbnail) ? fallback.thumbnail_text : resolvedThumbnail,
    hashtags: hashtags.length > 0 ? hashtags : fallback.hashtags,
  };
}

function pickMetadataObject(raw) {
  const root = raw && typeof raw === 'object' ? raw : null;
  if (!root) return null;

  const candidates = [
    root,
    root.metadata_output,
    root.metadata,
    root.output,
    root.data,
    root.result,
    root.response,
    root.payload,
    root.value,
    root.output?.metadata,
    root.output?.metadata_output,
    root.result?.metadata,
    root.result?.metadata_output,
    root.data?.metadata,
    root.data?.metadata_output,
  ];

  for (const candidate of candidates) {
    if (!candidate || typeof candidate !== 'object' || Array.isArray(candidate)) {
      continue;
    }

    const hasKnownKey =
      Object.prototype.hasOwnProperty.call(candidate, 'title') ||
      Object.prototype.hasOwnProperty.call(candidate, 'caption') ||
      Object.prototype.hasOwnProperty.call(candidate, 'thumbnail_text') ||
      Object.prototype.hasOwnProperty.call(candidate, 'hashtags');

    if (hasKnownKey) {
      return candidate;
    }
  }

  return null;
}

async function apiRequest(method, path, options = {}) {
  if (typeof requestHelper !== 'function') {
    throw new Error('Missing HTTP helper in Code node runtime.');
  }

  if (!n8nApiUrl || !n8nApiKey) {
    throw new Error('Missing n8n API URL or API key in workflow config.');
  }

  return await requestHelper({
    method,
    url: n8nApiUrl + path,
    headers: {
      'X-N8N-API-KEY': n8nApiKey,
    },
    qs: options.qs,
    body: options.body,
    json: true,
    timeout: 60000,
  });
}

async function ensureDataTable() {
  const list = await apiRequest('GET', '/api/v1/data-tables', {
    qs: { limit: 200 },
  });

  const tables = Array.isArray(list?.data) ? list.data : [];
  const existing = tables.find((table) => String(table?.name ?? '') === sessionStoreName);
  if (existing?.id) {
    return String(existing.id);
  }

  const created = await apiRequest('POST', '/api/v1/data-tables', {
    body: {
      name: sessionStoreName,
      columns: REQUIRED_COLUMNS,
    },
  });

  const id = String(created?.id ?? '').trim();
  if (!id) {
    throw new Error('Failed to create session data table.');
  }

  return id;
}

async function getSessionRow(tableId, sessionToken) {
  if (!sessionToken) return null;

  const rows = await apiRequest('GET', '/api/v1/data-tables/' + tableId + '/rows', {
    qs: {
      limit: 1,
      sortBy: 'updated_at:desc',
      filter: JSON.stringify({
        type: 'and',
        filters: [
          {
            columnName: 'session_token',
            condition: 'eq',
            value: sessionToken,
          },
        ],
      }),
    },
  });

  const data = Array.isArray(rows?.data) ? rows.data : [];
  return data[0] ?? null;
}

function deserializeSession(row) {
  if (!row || typeof row !== 'object') {
    return null;
  }

  const payload = safeJsonParse(row.payload_json, {}) ?? {};
  const payloadDriveContext = payload.drive_context && typeof payload.drive_context === 'object'
    ? payload.drive_context
    : {};

  const qcFromRow = safeJsonParse(row.qc_json, null);
  const metadataFromRow = safeJsonParse(row.metadata_json, null);
  const commandsFromRow = safeJsonParse(row.commands_json, null);

  const session = {
    session_token: safeText(row.session_token, safeText(payload.session_token)),
    stage: safeText(row.stage, safeText(payload.stage, 'review_pending')),
    deadline_at: safeText(row.deadline_at, safeText(payload.deadline_at)),
    awaiting_instruction: String(row.awaiting_instruction ?? payload.awaiting_instruction ?? '') === '1' || payload.awaiting_instruction === true,
    user_input: safeText(row.user_input, safeText(payload.user_input)),
    full_review: safeText(row.full_review, safeText(payload.review_readable, safeText(payload.full_review))),
    review_readable: safeText(payload.review_readable, safeText(row.full_review, safeText(payload.full_review))),
    review_manifest: payload.review_manifest && typeof payload.review_manifest === 'object' ? payload.review_manifest : null,
    review_intro: safeText(row.review_intro, safeText(payload.review_intro)),
    review_outro: safeText(row.review_outro, safeText(payload.review_outro)),
    review_round: asNumber(row.review_round, asNumber(payload.review_round, 0)),
    metadata_round: asNumber(row.metadata_round, asNumber(payload.metadata_round, 0)),
    stop_reason: safeText(row.stop_reason, safeText(payload.stop_reason)),
    updated_at: safeText(row.updated_at, safeText(payload.updated_at, nowIso())),
    turn_count: asNumber(payload.turn_count, 0),
    content_model: safeText(payload.content_model, ''),
    fallback_model: safeText(payload.fallback_model, ''),
    fallback_used: Boolean(payload.fallback_used),
    max_turns: asNumber(payload.max_turns, 8),
    qc_model: safeText(payload.qc_model, qcModel),
    qc_score_warning_threshold: asNumber(payload.qc_score_warning_threshold, qcScoreWarningThreshold),
    reviewer_wait_timeout_seconds: asNumber(payload.reviewer_wait_timeout_seconds, reviewerTimeoutSeconds),
    metadata_error: safeText(payload.metadata_error),
    ...mergeDriveContext(payloadDriveContext, payload),
  };

  session.qc = qcFromRow || payload.qc || null;
  session.metadata = metadataFromRow || payload.metadata || null;
  session.commands = Array.isArray(commandsFromRow)
    ? commandsFromRow
    : Array.isArray(payload.commands)
      ? payload.commands
      : [];

  return session;
}

function bootstrapSessionFromInput(sessionToken) {
  const fullReview = safeText(input.full_review, safeText(input.message));
  const reviewReadable = safeText(input.review_readable, fullReview);
  const reviewManifestFromInput = input.review_manifest && typeof input.review_manifest === 'object'
    ? input.review_manifest
    : null;
  const inputDriveContext = normalizeDriveContext(input);
  const metadataFromInput = input.metadata && typeof input.metadata === 'object'
    ? input.metadata
    : null;

  return {
    session_token: sessionToken,
    stage: 'media_pending',
    deadline_at: addSeconds(nowIso(), reviewerTimeoutSeconds),
    awaiting_instruction: false,
    user_input: safeText(input.user_input),
    full_review: reviewReadable,
    review_readable: reviewReadable,
    review_manifest: reviewManifestFromInput,
    review_intro: safeText(input.review_intro, extractSectionText(fullReview, 'intro')),
    review_outro: safeText(input.review_outro, extractSectionText(fullReview, 'outro')),
    qc: null,
    metadata: metadataFromInput,
    review_round: 0,
    metadata_round: 0,
    commands: [],
    stop_reason: safeText(input.stop_reason),
    updated_at: nowIso(),
    turn_count: asNumber(input.turn_count, 0),
    content_model: safeText(input.content_model),
    fallback_model: safeText(input.fallback_model),
    fallback_used: Boolean(input.fallback_used),
    max_turns: asNumber(input.max_turns, 8),
    qc_model: safeText(input.qc_model, qcModel),
    qc_score_warning_threshold: asNumber(input.qc_score_warning_threshold, qcScoreWarningThreshold),
    reviewer_wait_timeout_seconds: asNumber(input.reviewer_wait_timeout_seconds, reviewerTimeoutSeconds),
    metadata_error: '',
    ...inputDriveContext,
  };
}

function serializeSession(session) {
  const qcJson = safeJsonStringify(session.qc ?? {}, '{}');
  const metadataJson = safeJsonStringify(session.metadata ?? {}, '{}');
  const commands = Array.isArray(session.commands) ? session.commands.slice(-200) : [];
  const commandsJson = safeJsonStringify(commands, '[]');

  const payload = {
    session_token: session.session_token,
    stage: session.stage,
    deadline_at: session.deadline_at,
    awaiting_instruction: session.awaiting_instruction === true,
    user_input: session.user_input,
    full_review: session.full_review,
    review_readable: safeText(session.review_readable, safeText(session.full_review)),
    review_manifest: session.review_manifest && typeof session.review_manifest === 'object' ? session.review_manifest : null,
    review_intro: session.review_intro,
    review_outro: session.review_outro,
    review_round: asNumber(session.review_round, 0),
    metadata_round: asNumber(session.metadata_round, 0),
    stop_reason: session.stop_reason,
    updated_at: session.updated_at,
    turn_count: asNumber(session.turn_count, 0),
    content_model: session.content_model,
    fallback_model: session.fallback_model,
    fallback_used: Boolean(session.fallback_used),
    max_turns: asNumber(session.max_turns, 8),
    qc_model: session.qc_model,
    qc_score_warning_threshold: asNumber(session.qc_score_warning_threshold, qcScoreWarningThreshold),
    reviewer_wait_timeout_seconds: asNumber(session.reviewer_wait_timeout_seconds, reviewerTimeoutSeconds),
    metadata_error: safeText(session.metadata_error),
    session_folder_id: safeText(session.session_folder_id),
    session_folder_url: safeText(session.session_folder_url),
    session_voice_folder_id: safeText(session.session_voice_folder_id),
    session_voice_folder_url: safeText(session.session_voice_folder_url),
    session_image_folder_id: safeText(session.session_image_folder_id),
    session_image_folder_url: safeText(session.session_image_folder_url),
    session_review_file_id: safeText(session.session_review_file_id),
    session_review_file_url: safeText(session.session_review_file_url),
    session_metadata_file_id: safeText(session.session_metadata_file_id),
    session_metadata_file_url: safeText(session.session_metadata_file_url),
    session_manifest_file_id: safeText(session.session_manifest_file_id),
    session_manifest_file_url: safeText(session.session_manifest_file_url),
    session_sheet_id: safeText(session.session_sheet_id),
    session_sheet_url: safeText(session.session_sheet_url),
    drive_context: normalizeDriveContext(session),
    qc: session.qc ?? null,
    metadata: session.metadata ?? null,
    commands,
  };

  return {
    session_token: session.session_token,
    stage: safeText(session.stage, 'review_pending'),
    deadline_at: safeText(session.deadline_at),
    awaiting_instruction: session.awaiting_instruction === true ? '1' : '',
    user_input: safeText(session.user_input),
    full_review: safeText(session.review_readable, safeText(session.full_review)),
    review_intro: safeText(session.review_intro),
    review_outro: safeText(session.review_outro),
    qc_json: qcJson,
    metadata_json: metadataJson,
    review_round: asNumber(session.review_round, 0),
    metadata_round: asNumber(session.metadata_round, 0),
    commands_json: commandsJson,
    stop_reason: safeText(session.stop_reason),
    updated_at: safeText(session.updated_at, nowIso()),
    payload_json: safeJsonStringify(payload, '{}'),
  };
}

async function saveSession(tableId, session) {
  const rowData = serializeSession(session);

  await apiRequest('POST', '/api/v1/data-tables/' + tableId + '/rows/upsert', {
    body: {
      filter: {
        type: 'and',
        filters: [
          {
            columnName: 'session_token',
            condition: 'eq',
            value: rowData.session_token,
          },
        ],
      },
      data: rowData,
      returnData: false,
    },
  });
}

function appendCommand(session, command) {
  if (!Array.isArray(session.commands)) {
    session.commands = [];
  }

  session.commands.push({
    ts: nowIso(),
    source: sourceInput,
    event_type: eventType,
    ...command,
  });

  if (session.commands.length > 400) {
    session.commands = session.commands.slice(-400);
  }
}

async function callOpenAI(messages, options = {}) {
  if (!proxyBaseUrl || !proxyApiKey || typeof requestHelper !== 'function') {
    throw new Error('Missing proxy/OpenAI configuration or HTTP helper.');
  }

  const body = {
    model: qcModel,
    messages,
    stream: false,
  };

  if (options.jsonObject === true) {
    body.response_format = { type: 'json_object' };
  }

  return await requestHelper({
    method: 'POST',
    url: proxyBaseUrl + '/v1/chat/completions',
    headers: {
      Authorization: 'Bearer ' + proxyApiKey,
    },
    body,
    json: true,
    timeout: Number(options.timeoutMs ?? 180000),
  });
}

async function generateMetadataBundle(session, instruction, previousMetadata) {
  const reviewerInstruction = safeText(instruction);
  const adjustedInstruction = ensureKeepOthersInstruction(reviewerInstruction);
  const requestedTargets = detectMetadataTargets(adjustedInstruction);

  const promptPayload = {
    task: previousMetadata
      ? 'Refine existing metadata for a Vietnamese book-review video.'
      : 'Generate metadata for a Vietnamese book-review video.',
    requirements: {
      output: 'json_only',
      fields: ['title', 'caption', 'thumbnail_text', 'hashtags'],
      style: 'high-retention, concrete, non-clickbait',
      language: 'vi',
      keep_unmentioned_fields: true,
      never_output_fields: ['youtube_description_long', 'description', 'video_description'],
    },
    request: safeText(session.user_input),
    reviewer_instruction: adjustedInstruction,
    previous_metadata: previousMetadata ?? null,
    review_excerpt: safeText(normalizeReviewForDisplay(session.full_review)),
  };

  const systemPrompt = safeText(
    metadataPromptTemplate,
    'You are a short-video growth strategist. Return JSON only with exactly these keys: title, caption, thumbnail_text, hashtags.'
  );

  const response = await callOpenAI([
    {
      role: 'system',
      content: systemPrompt,
    },
    {
      role: 'user',
      content: JSON.stringify(promptPayload),
    },
  ], { jsonObject: true });

  const content = String(response?.choices?.[0]?.message?.content ?? '').trim();
  const parsed = parseJsonObject(content);
  if (!parsed || typeof parsed !== 'object') {
    throw new Error('Metadata response is not valid JSON object.');
  }

  const metadataCandidate = pickMetadataObject(parsed);
  if (!metadataCandidate) {
    const keys = Object.keys(parsed).slice(0, 8).join(', ');
    throw new Error('Metadata response missing required keys. top_level_keys=' + (keys || 'none'));
  }

  const previousNormalized = previousMetadata && typeof previousMetadata === 'object'
    ? normalizeMetadataBundle(previousMetadata, previousMetadata, session)
    : null;

  const resolved = {
    title: safeText(metadataCandidate.title, safeText(previousNormalized?.title)),
    caption: safeText(metadataCandidate.caption, safeText(previousNormalized?.caption)),
    thumbnail_text: safeText(metadataCandidate.thumbnail_text, safeText(previousNormalized?.thumbnail_text)),
    hashtags: normalizeHashtags(
      metadataCandidate.hashtags ?? previousNormalized?.hashtags ?? [],
    ),
  };

  if (isMetadataPlaceholderValue(resolved.title)) {
    resolved.title = safeText(previousNormalized?.title);
  }
  if (isMetadataPlaceholderValue(resolved.caption)) {
    resolved.caption = safeText(previousNormalized?.caption);
  }
  if (isMetadataPlaceholderValue(resolved.thumbnail_text)) {
    resolved.thumbnail_text = safeText(previousNormalized?.thumbnail_text);
  }

  if (resolved.hashtags.length === 0) {
    resolved.hashtags = normalizeHashtags(previousNormalized?.hashtags ?? []);
  }

  const missingFields = [];
  if (!safeText(resolved.title)) missingFields.push('title');
  if (!safeText(resolved.caption)) missingFields.push('caption');
  if (!safeText(resolved.thumbnail_text)) missingFields.push('thumbnail_text');
  if (missingFields.length > 0) {
    throw new Error('Metadata missing required fields: ' + missingFields.join(', '));
  }

  const hasSelectiveInstruction =
    Boolean(previousMetadata) &&
    adjustedInstruction.length > 0 &&
    requestedTargets.size > 0 &&
    requestedTargets.size < METADATA_FIELDS.length;

  if (hasSelectiveInstruction) {
    if (!requestedTargets.has('title')) {
      resolved.title = safeText(previousMetadata?.title, resolved.title);
    }
    if (!requestedTargets.has('caption')) {
      resolved.caption = safeText(previousMetadata?.caption, resolved.caption);
    }
    if (!requestedTargets.has('thumbnail_text')) {
      resolved.thumbnail_text = safeText(previousMetadata?.thumbnail_text, resolved.thumbnail_text);
    }
    if (!requestedTargets.has('hashtags')) {
      resolved.hashtags = Array.isArray(previousMetadata?.hashtags) && previousMetadata.hashtags.length > 0
        ? previousMetadata.hashtags
        : resolved.hashtags;
    }
  }

  if (resolved.hashtags.length === 0) {
    resolved.hashtags = buildMetadataFallbackTags([], session);
  }

  return resolved;
}

async function telegramApi(method, params = {}, useGet = false) {
  if (!telegramBotToken || typeof requestHelper !== 'function') {
    return null;
  }

  return await requestHelper({
    method: useGet ? 'GET' : 'POST',
    url: 'https://api.telegram.org/bot' + telegramBotToken + '/' + method,
    qs: useGet ? params : undefined,
    body: useGet ? undefined : params,
    json: true,
    timeout: 60000,
  });
}

async function answerCallback(callbackId, text) {
  const id = safeText(callbackId);
  if (!id) return;
  const normalizedText = safeText(text).slice(0, 180);
  const payload = {
    callback_query_id: id,
    show_alert: false,
  };
  if (normalizedText) {
    payload.text = normalizedText;
  }

  try {
    await telegramApi('answerCallbackQuery', payload, false);
  } catch (_) {}
}

async function lockCallbackActionMessage(callbackChatId, callbackMessageId, text) {
  const chatId = safeText(callbackChatId);
  const messageId = Number(callbackMessageId);
  if (!chatId || !Number.isFinite(messageId) || messageId <= 0) return;

  try {
    await telegramApi('editMessageReplyMarkup', {
      chat_id: chatId,
      message_id: Math.floor(messageId),
      reply_markup: {
        inline_keyboard: [],
      },
    }, false);
  } catch (_) {}
}

function isPendingReviewerStage(stageValue) {
  const stage = safeText(stageValue).toLowerCase();
  return stage === 'media_pending' || stage === 'review_pending' || stage === 'metadata_pending';
}

function isSessionTimedOut(session) {
  if (!session || !isPendingReviewerStage(session.stage)) {
    return false;
  }

  const deadlineText = safeText(session.deadline_at);
  if (!deadlineText) {
    return false;
  }

  const deadlineMs = Date.parse(deadlineText);
  if (!Number.isFinite(deadlineMs)) {
    return false;
  }

  return Date.now() > deadlineMs;
}

function buildTimeoutActionText(session) {
  const stage = safeText(session?.stage).toLowerCase();
  if (stage === 'media_pending') {
    return 'Da qua thoi gian cho tao media, nhung van tiep tuc xu ly theo yeu cau.';
  }
  if (stage === 'metadata_pending') {
    return 'Da qua thoi gian cho metadata, nhung van tiep tuc xu ly theo yeu cau.';
  }

  return 'Da qua thoi gian cho review, nhung van tiep tuc xu ly theo yeu cau.';
}

function buildSessionNotFoundActionText() {
  return 'Session khong con hieu luc.';
}

function buildActionInfoText(eventType, instructionText) {
  if (eventType === 'review_continue' || eventType === 'metadata_continue' || eventType === 'media_continue') {
    return '';
  }
  if (eventType === 'review_stop' || eventType === 'metadata_stop' || eventType === 'media_stop') {
    return 'Da ghi nhan dung.';
  }

  return 'Da ghi nhan thao tac.';
}

async function sendTelegramMessage(text, inlineKeyboardRows) {
  if (!telegramBotToken || !telegramChatId || typeof requestHelper !== 'function') {
    return null;
  }

  const payload = {
    chat_id: telegramChatId,
    text: String(text ?? '').slice(0, telegramMessageTextLimit),
  };

  if (Array.isArray(inlineKeyboardRows) && inlineKeyboardRows.length > 0) {
    payload.reply_markup = {
      inline_keyboard: inlineKeyboardRows,
    };
  }

  return await telegramApi('sendMessage', payload, false);
}

async function deleteTelegramMessage(messageId, chatIdOverride = '') {
  const chatId = safeText(chatIdOverride, telegramChatId);
  const normalizedMessageId = Number(messageId);
  if (!chatId || !Number.isFinite(normalizedMessageId) || normalizedMessageId <= 0) {
    return false;
  }

  try {
    await telegramApi('deleteMessage', {
      chat_id: chatId,
      message_id: Math.floor(normalizedMessageId),
    }, false);
    return true;
  } catch (_) {
    return false;
  }
}

function formatStepProgressText(stepText, estimatedMinutes, elapsedSecondsInput, prefix = '') {
  const normalizedStepText = safeText(stepText);
  const normalizedPrefix = safeText(prefix);
  const estimate = Math.max(1, Math.floor(Number(estimatedMinutes) || 1));
  const elapsedSeconds = Math.max(0, Math.floor(Number(elapsedSecondsInput) || 0));
  const elapsedMinutes = Math.floor(elapsedSeconds / 60);
  const remainingSeconds = elapsedSeconds % 60;
  const elapsedLabel = elapsedMinutes > 0
    ? (elapsedMinutes + ' phut ' + String(remainingSeconds).padStart(2, '0') + ' giay')
    : (remainingSeconds + ' giay');
  const core = normalizedStepText + ' (da cho ' + elapsedLabel + ' / du kien ' + estimate + ' phut)';
  return normalizedPrefix ? (normalizedPrefix + '\n' + core) : core;
}

async function editTelegramMessage(messageId, text, chatIdOverride = '') {
  const chatId = safeText(chatIdOverride, telegramChatId);
  const normalizedMessageId = Number(messageId);
  const normalizedText = safeText(text);
  if (!chatId || !Number.isFinite(normalizedMessageId) || normalizedMessageId <= 0 || !normalizedText) {
    return false;
  }

  try {
    await telegramApi('editMessageText', {
      chat_id: chatId,
      message_id: Math.floor(normalizedMessageId),
      text: normalizedText.slice(0, telegramMessageTextLimit),
      disable_web_page_preview: true,
    }, false);
    return true;
  } catch (_) {
    return false;
  }
}

async function sendStepProgressMessage(stepText, estimatedMinutes = 1, options = {}) {
  const normalizedStepText = safeText(stepText);
  if (!normalizedStepText) {
    return null;
  }

  const minutes = Math.max(1, Math.floor(Number(estimatedMinutes) || 1));
  const prefix = safeText(options.prefix);
  const text = formatStepProgressText(normalizedStepText, minutes, 0, prefix);

  try {
    const response = await sendTelegramMessage(text);
    const messageId = Number(response?.result?.message_id);
    const normalizedMessageId = Number.isFinite(messageId) && messageId > 0
      ? Math.floor(messageId)
      : null;
    if (!normalizedMessageId) {
      return null;
    }

    return {
      message_id: normalizedMessageId,
      chat_id: safeText(options.chatId, telegramChatId),
      step_text: normalizedStepText,
      estimated_minutes: minutes,
      prefix,
      started_at_ms: Date.now(),
    };
  } catch (_) {
    return null;
  }
}

async function withStepProgressMessage(stepText, estimatedMinutes, workerFn, options = {}) {
  const progressMessage = await sendStepProgressMessage(stepText, estimatedMinutes, options);
  let timerId = null;

  if (progressMessage?.message_id) {
    let inFlightUpdate = false;
    timerId = setInterval(() => {
      if (inFlightUpdate) {
        return;
      }

      inFlightUpdate = true;
      const elapsedSeconds = Math.floor((Date.now() - Number(progressMessage.started_at_ms || Date.now())) / 1000);
      const updatedText = formatStepProgressText(
        progressMessage.step_text,
        progressMessage.estimated_minutes,
        elapsedSeconds,
        progressMessage.prefix,
      );

      void editTelegramMessage(
        progressMessage.message_id,
        updatedText,
        progressMessage.chat_id,
      ).finally(() => {
        inFlightUpdate = false;
      });
    }, 3000);
  }

  try {
    return await workerFn();
  } finally {
    if (timerId) {
      clearInterval(timerId);
    }
    if (progressMessage?.message_id) {
      await deleteTelegramMessage(progressMessage.message_id, progressMessage.chat_id);
    }
  }
}

if (!eventType) {
  return {
    status: 'skipped',
    stop_reason: 'missing_event_type',
    event_type: '',
    source: sourceInput,
    session_token: sessionTokenInput,
    notify_message: '',
  };
}

let tableId = '';
let saveError = '';
let workerError = '';
let notifyMessage = '';
const pendingProgressMessageIds = [];
let ttsProgressMessageId = null;
let ttsProgressStartedAtMs = null;
let ttsProgressEstimatedMinutes = 3;
let imageProgressMessageId = null;
let imageProgressStartedAtMs = null;
let imageProgressEstimatedMinutes = 3;
let shouldSendQcAction = false;
let qcActionHeadline = 'QC REVIEW';
let shouldSendMetadataAction = false;
let metadataActionHeadline = 'SAN SANG TAO MEDIA';

try {
  tableId = await ensureDataTable();
} catch (error) {
  workerError = error?.message ? String(error.message) : String(error);
}

const hasTelegramCallback = sourceInput === 'telegram' && safeText(input.callback_id).length > 0;

if (!tableId) {
  if (hasTelegramCallback) {
    const callbackErrorText = 'He thong dang ban. Thu lai sau.';
    await answerCallback(input.callback_id, callbackErrorText);
    await lockCallbackActionMessage(input.callback_chat_id, input.callback_message_id, callbackErrorText);
  }

  return {
    ...input,
    status: 'failed',
    stop_reason: 'datastore_error',
    notify_message: 'Worker cannot access data store: ' + workerError,
  };
}

const sessionToken = safeText(sessionTokenInput, safeText(input.reviewer_session_token));
let session = null;

if (sessionToken) {
  const row = await getSessionRow(tableId, sessionToken);
  session = deserializeSession(row);
}

if (!session && eventType === 'init_review' && sessionToken) {
  session = bootstrapSessionFromInput(sessionToken);
}

if (!session) {
  if (hasTelegramCallback) {
    const missingSessionText = buildSessionNotFoundActionText();
    await answerCallback(input.callback_id, missingSessionText);
    await lockCallbackActionMessage(input.callback_chat_id, input.callback_message_id, missingSessionText);
  }

  return {
    ...input,
    status: 'failed',
    stop_reason: 'session_not_found',
    session_token: sessionToken,
    notify_message: 'Session not found for event ' + eventType + '. token=' + sessionToken,
  };
}

const resolvedDriveContext = mergeDriveContext(
  normalizeDriveContext(session),
  normalizeDriveContext(input),
);
Object.assign(session, resolvedDriveContext);

session.review_readable = safeText(session.review_readable, safeText(session.full_review));
session.full_review = safeText(session.review_readable, safeText(session.full_review));
if ((!session.review_manifest || typeof session.review_manifest !== 'object') && input.review_manifest && typeof input.review_manifest === 'object') {
  session.review_manifest = input.review_manifest;
}

const timedOutSession = hasTelegramCallback && isSessionTimedOut(session);

if (hasTelegramCallback) {
  const actionInfoText = timedOutSession
    ? buildTimeoutActionText(session)
    : buildActionInfoText(eventType, instructionInput);
  await answerCallback(input.callback_id, actionInfoText);
  await lockCallbackActionMessage(input.callback_chat_id, input.callback_message_id, actionInfoText);
}

if (timedOutSession) {
  appendCommand(session, {
    stage: safeText(session.stage, 'media_pending'),
    action: 'timeout_override_continue',
    instruction: '',
  });
}

if (!session.review_intro) {
  session.review_intro = extractSectionText(session.full_review, 'intro');
}
if (!session.review_outro) {
  session.review_outro = extractSectionText(session.full_review, 'outro');
}

const instructionText = safeText(instructionInput);
const normalizedEventType =
  eventType === 'review_continue' || eventType === 'metadata_continue' ? 'media_continue' :
  eventType === 'auto_continue_review' || eventType === 'auto_continue_metadata' ? 'auto_continue_media' :
  eventType === 'review_stop' || eventType === 'metadata_stop' ? 'media_stop' :
  eventType;

try {
  if (normalizedEventType === 'init_review') {
    if (!session.full_review) {
      throw new Error('Session has empty review content.');
    }

    session.stage = 'media_pending';
    session.awaiting_instruction = false;
    session.deadline_at = addSeconds(nowIso(), reviewerTimeoutSeconds);
    session.stop_reason = '';
    session.metadata_error = '';

    const metadataFromInput = input.metadata && typeof input.metadata === 'object'
      ? input.metadata
      : null;

    if (metadataFromInput) {
      session.metadata = normalizeMetadataBundle(metadataFromInput, session.metadata, session);
    }

    const metadataNeedsGeneration =
      !session.metadata
      || !safeText(session.metadata.title)
      || !safeText(session.metadata.caption)
      || isMetadataPlaceholderBundle(session.metadata);

    if (metadataNeedsGeneration) {
      try {
        session.metadata = await generateMetadataBundle(session, '', session.metadata ?? null);
        session.metadata = normalizeMetadataBundle(session.metadata, session.metadata, session);
        session.metadata_error = '';
      } catch (error) {
        const errorText = error?.message ? String(error.message) : String(error);
        session.metadata_error = errorText;
        session.metadata = normalizeMetadataBundle(
          defaultMetadataFallback(session.metadata, session),
          session.metadata,
          session,
        );
      }
    } else {
      session.metadata = normalizeMetadataBundle(session.metadata, session.metadata, session);
    }

    appendCommand(session, {
      stage: 'media',
      action: 'init',
      instruction: '',
    });

    shouldSendQcAction = true;
    qcActionHeadline = 'QC REVIEW';
    shouldSendMetadataAction = true;
    metadataActionHeadline = 'SAN SANG TAO MEDIA';

    notifyMessage = 'Review va metadata da san sang, dang cho lenh tao media.';
  } else if (normalizedEventType === 'media_continue' || normalizedEventType === 'auto_continue_media') {
    session.awaiting_instruction = false;
    session.stage = 'completed';
    session.deadline_at = '';
    session.stop_reason = 'completed';

    appendCommand(session, {
      stage: 'media',
      action: normalizedEventType === 'auto_continue_media' ? 'auto_continue' : 'continue',
      instruction: '',
    });

    const ttsProgressMessage = await sendStepProgressMessage('Dang tao TTS...', 3);
    if (Number.isFinite(Number(ttsProgressMessage?.message_id))) {
      ttsProgressMessageId = Math.floor(Number(ttsProgressMessage.message_id));
      pendingProgressMessageIds.push(ttsProgressMessageId);
      const startedAtMs = Number(ttsProgressMessage?.started_at_ms);
      if (Number.isFinite(startedAtMs) && startedAtMs > 0) {
        ttsProgressStartedAtMs = Math.floor(startedAtMs);
      }
      const estimatedMinutes = Number(ttsProgressMessage?.estimated_minutes);
      if (Number.isFinite(estimatedMinutes) && estimatedMinutes > 0) {
        ttsProgressEstimatedMinutes = Math.floor(estimatedMinutes);
      }
    }

    const imageProgressMessage = await sendStepProgressMessage('Dang tao anh...', 3);
    if (Number.isFinite(Number(imageProgressMessage?.message_id))) {
      imageProgressMessageId = Math.floor(Number(imageProgressMessage.message_id));
      pendingProgressMessageIds.push(imageProgressMessageId);
      const imageStartedAtMs = Number(imageProgressMessage?.started_at_ms);
      if (Number.isFinite(imageStartedAtMs) && imageStartedAtMs > 0) {
        imageProgressStartedAtMs = Math.floor(imageStartedAtMs);
      }
      const imageEstimatedMinutes = Number(imageProgressMessage?.estimated_minutes);
      if (Number.isFinite(imageEstimatedMinutes) && imageEstimatedMinutes > 0) {
        imageProgressEstimatedMinutes = Math.floor(imageEstimatedMinutes);
      }
    }

    notifyMessage = normalizedEventType === 'auto_continue_media'
      ? 'Auto-continued media stage and started media pipeline.'
      : 'Media approved. Started media pipeline (TTS + image).';
  } else if (normalizedEventType === 'media_stop') {
    session.awaiting_instruction = false;
    session.stage = 'completed';
    session.deadline_at = '';
    session.stop_reason = 'reviewer_stopped';

    appendCommand(session, {
      stage: 'media',
      action: 'stop',
      instruction: '',
    });

    await sendTelegramMessage('Da dung luong tao media theo yeu cau reviewer. Session: ' + session.session_token);
    notifyMessage = 'Reviewer stopped at media stage.';
  } else {
    throw new Error('Unsupported event_type: ' + normalizedEventType);
  }
} catch (error) {
  workerError = error?.message ? String(error.message) : String(error);
  appendCommand(session, {
    stage: String(session.stage ?? 'unknown'),
    action: 'worker_error',
    instruction: instructionText,
    error: workerError,
  });
  notifyMessage = 'Worker error: ' + workerError;
  session.stop_reason = session.stop_reason || 'worker_error';
}

session.updated_at = nowIso();

if (session.stage === 'completed' && !session.stop_reason) {
  session.stop_reason = 'completed';
}

const qc = session.qc ?? null;
const metadata = session.metadata ?? null;

try {
  await saveSession(tableId, session);
} catch (error) {
  saveError = error?.message ? String(error.message) : String(error);
}

const status = workerError || saveError ? 'failed' : 'success';
const finalNotifyMessage = [notifyMessage, workerError ? 'worker_error=' + workerError : '', saveError ? 'save_error=' + saveError : '']
  .filter(Boolean)
  .join(' | ')
  .slice(0, 1200);

return {
  ...input,
  status,
  event_type: normalizedEventType,
  source: sourceInput,
  session_token: session.session_token,
  reviewer_stage: session.stage,
  stop_reason: session.stop_reason || '',
  notify_message: finalNotifyMessage || 'Worker processed event.',
  worker_error: workerError || null,
  save_error: saveError || null,
  full_review: safeText(session.review_readable, safeText(session.full_review)),
  review_readable: safeText(session.review_readable, safeText(session.full_review)),
  review_manifest: session.review_manifest && typeof session.review_manifest === 'object' ? session.review_manifest : null,
  review_intro: session.review_intro,
  review_outro: session.review_outro,
  metadata: metadata,
  metadata_status: metadata ? 'generated' : session.stage === 'media_pending' ? 'pending' : 'skip',
  metadata_error: session.metadata_error || null,
  video_title: safeText(metadata?.title),
  video_caption: safeText(metadata?.caption),
  video_thumbnail_text: safeText(metadata?.thumbnail_text),
  video_hashtags: Array.isArray(metadata?.hashtags) ? metadata.hashtags : [],
  qc_status: qc?.qc_status ?? 'missing',
  hook_score: qc?.hook_score ?? null,
  clarity_score: qc?.clarity_score ?? null,
  originality_score: qc?.originality_score ?? null,
  practical_value_score: qc?.practical_value_score ?? null,
  risk_level: qc?.risk_level ?? 'med',
  feedback: safeText(qc?.feedback),
  score_warnings: Array.isArray(qc?.score_warnings) ? qc.score_warnings : [],
  reviewer_commands: Array.isArray(session.commands) ? session.commands : [],
  should_send_qc_action: shouldSendQcAction,
  qc_action_headline: shouldSendQcAction ? qcActionHeadline : '',
  should_send_metadata_action: shouldSendMetadataAction,
  metadata_action_headline: shouldSendMetadataAction ? metadataActionHeadline : '',
  should_send_media_action: shouldSendMetadataAction,
  media_action_headline: shouldSendMetadataAction ? metadataActionHeadline : '',
  session_folder_id: safeText(session.session_folder_id),
  session_folder_url: safeText(session.session_folder_url),
  session_voice_folder_id: safeText(session.session_voice_folder_id),
  session_voice_folder_url: safeText(session.session_voice_folder_url),
  session_image_folder_id: safeText(session.session_image_folder_id),
  session_image_folder_url: safeText(session.session_image_folder_url),
  session_review_file_id: safeText(session.session_review_file_id),
  session_review_file_url: safeText(session.session_review_file_url),
  session_metadata_file_id: safeText(session.session_metadata_file_id),
  session_metadata_file_url: safeText(session.session_metadata_file_url),
  session_manifest_file_id: safeText(session.session_manifest_file_id),
  session_manifest_file_url: safeText(session.session_manifest_file_url),
  session_sheet_id: safeText(session.session_sheet_id),
  session_sheet_url: safeText(session.session_sheet_url),
  tts_progress_message_id: Number.isFinite(Number(ttsProgressMessageId)) ? Math.floor(Number(ttsProgressMessageId)) : null,
  tts_progress_started_at_ms: Number.isFinite(Number(ttsProgressStartedAtMs)) ? Math.floor(Number(ttsProgressStartedAtMs)) : null,
  tts_progress_estimated_minutes: Number.isFinite(Number(ttsProgressEstimatedMinutes))
    ? Math.max(1, Math.floor(Number(ttsProgressEstimatedMinutes)))
    : 3,
  image_progress_message_id: Number.isFinite(Number(imageProgressMessageId)) ? Math.floor(Number(imageProgressMessageId)) : null,
  image_progress_started_at_ms: Number.isFinite(Number(imageProgressStartedAtMs)) ? Math.floor(Number(imageProgressStartedAtMs)) : null,
  image_progress_estimated_minutes: Number.isFinite(Number(imageProgressEstimatedMinutes))
    ? Math.max(1, Math.floor(Number(imageProgressEstimatedMinutes)))
    : 3,
  pending_progress_message_ids: pendingProgressMessageIds,
};

const input = $json ?? {};

