const input = $json ?? {};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function asInt(value, fallback = 0, min = 0, max = 1000000) {
  const number = Number(value);
  const normalized = Number.isFinite(number) ? Math.floor(number) : fallback;
  return Math.min(max, Math.max(min, normalized));
}

function normalizeText(value) {
  return String(value ?? '').replace(/\r\n/g, '\n').trim();
}

function tokenizeSentences(text) {
  const normalized = normalizeText(text).replace(/\s+/g, ' ');
  if (!normalized) return [];
  const matches = normalized.match(/[^.!?…]+(?:[.!?…]+(?:["'”’)\]]+)*)|[^.!?…]+$/g) ?? [];
  const list = matches.map((item) => item.trim()).filter(Boolean);
  return list.length > 0 ? list : [normalized];
}

function normalizeScene(scene, index) {
  const source = scene && typeof scene === 'object' ? scene : {};
  const order = asInt(source.order, index + 1, 1, 100);
  const sceneId = safeText(source.scene_id, 'scene_' + String(order).padStart(2, '0'));
  const narrationText = normalizeText(source.narration_text);

  return {
    scene_id: sceneId,
    order,
    scene_title: safeText(source.scene_title, 'Phan canh ' + String(order).padStart(2, '0')),
    scene_role: safeText(source.scene_role, order === 1 ? 'hook' : 'core'),
    narration_text: narrationText,
    image_prompt_en: safeText(source.image_prompt_en, 'cinematic storytelling illustration, warm light, emotional depth'),
    highlight_quote_vi: safeText(source.highlight_quote_vi),
    estimated_duration_sec: asInt(source.estimated_duration_sec, order === 1 ? 60 : 95, 15, 300),
    transition: safeText(source.transition, 'cut'),
    chunk_key: sceneId,
    partName: sceneId,
    index: order,
    text: narrationText,
    sentence_count: Math.max(1, tokenizeSentences(narrationText).length),
    chunk_type: 'scene',
  };
}

const manifest = input.review_manifest && typeof input.review_manifest === 'object'
  ? input.review_manifest
  : {};
const scenesRaw = Array.isArray(manifest.scenes) ? manifest.scenes : [];
const mediaChunks = scenesRaw
  .map((scene, idx) => normalizeScene(scene, idx))
  .filter((scene) => safeText(scene.narration_text) !== '');

const hasScenes = mediaChunks.length > 0;
const eventType = safeText(input.event_type).toLowerCase();
const isMediaApprovedEvent = [
  'media_continue',
  'auto_continue_media',
  'metadata_continue',
  'auto_continue_metadata',
].includes(eventType);

const mediaVisualModeRaw = safeText(input.media_visual_mode, 'image').toLowerCase();
const mediaVisualMode = mediaVisualModeRaw === 'video' ? 'video' : 'image';
const hasImageProvider = safeText(input.image_api_base_url) !== '';
const hasVideoProvider = safeText(input.video_api_base_url, safeText(input.image_api_base_url)) !== '';
const hasVisualProvider = mediaVisualMode === 'video' ? hasVideoProvider : hasImageProvider;
const hasTtsProvider = safeText(input.tts_api_base_url, 'http://127.0.0.1:8001') !== '';

const runImage = isMediaApprovedEvent && hasScenes && hasVisualProvider;
const runTts = isMediaApprovedEvent && hasScenes && hasTtsProvider;
const runAny = runImage || runTts;

const defaultOutputFolder = safeText(
  input.media_output_folder_id,
