  drive_output_folder_id: defaultOutputFolder,
  image_progress_total_files: runImage ? mediaChunks.length : 0,
  tts_progress_total_files: runTts ? mediaChunks.length : 0,
  media_assets: runAny ? [] : (Array.isArray(input.media_assets) ? input.media_assets : []),
  media_debug_full: runAny ? [] : (Array.isArray(input.media_debug_full) ? input.media_debug_full : []),
  media_pipeline_status: pipelineStatus,
  media_debug_phase: runAny ? 'prepared' : 'skipped_prepared',
  media_started_at: runAny ? new Date().toISOString() : (input.media_started_at ?? null),
};

const input = $json ?? {};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function asInt(value, fallback = 0, min = 0, max = 1000000) {
  const number = Number(value);
  const normalized = Number.isFinite(number) ? Math.floor(number) : fallback;
  return Math.min(max, Math.max(min, normalized));
}

function asDuration(value, fallback = 0) {
  const number = Number(value);
  if (!Number.isFinite(number) || number < 0) return fallback;
  return Math.round(number * 1000) / 1000;
}

function computeElapsedSeconds(startedAt, finishedAtIso) {
  const started = new Date(startedAt ?? '');
  const finished = new Date(finishedAtIso ?? '');
  if (Number.isNaN(started.getTime()) || Number.isNaN(finished.getTime())) return 0;
  const elapsed = (finished.getTime() - started.getTime()) / 1000;
  if (!Number.isFinite(elapsed) || elapsed < 0) return 0;
  return Math.round(elapsed * 1000) / 1000;
}

function normalizeScene(scene, index) {
  const source = scene && typeof scene === 'object' ? scene : {};
  const order = asInt(source.order, index + 1, 1, 100);
  const sceneId = safeText(source.scene_id, safeText(source.chunk_key, 'scene_' + String(order).padStart(2, '0')));
  return {
    scene_id: sceneId,
    order,
    scene_title: safeText(source.scene_title, 'Phan canh ' + String(order).padStart(2, '0')),
    scene_role: safeText(source.scene_role, order === 1 ? 'hook' : 'core'),
    narration_text: safeText(source.narration_text, safeText(source.text)),
    image_prompt_en: safeText(source.image_prompt_en),
    highlight_quote_vi: safeText(source.highlight_quote_vi),
    estimated_duration_sec: asDuration(source.estimated_duration_sec, order === 1 ? 60 : 95),
    transition: safeText(source.transition, 'cut'),
    chunk_key: safeText(source.chunk_key, sceneId),
    partName: safeText(source.partName, sceneId),
    index: asInt(source.index, order, 1, 100),
    text: safeText(source.text, safeText(source.narration_text)),
  };
}

const chunksFromInput = Array.isArray(input.media_chunks) ? input.media_chunks : [];
const baseScenes = chunksFromInput.map((scene, idx) => normalizeScene(scene, idx));

const visualMode = safeText(input.media_visual_mode, 'image').toLowerCase() === 'video'
  ? 'video'
  : 'image';

const videoItems = Array.isArray(input.media_video_items) ? input.media_video_items : [];
const imageItems = Array.isArray(input.media_image_items) ? input.media_image_items : [];
const visualItems = videoItems.length > 0 ? videoItems : imageItems;
const ttsItems = Array.isArray(input.media_tts_items) ? input.media_tts_items : [];

const shouldRun = input.media_should_run === true || visualItems.length > 0 || ttsItems.length > 0;
if (!shouldRun) {
  const finishedAt = new Date().toISOString();
  return {
    ...input,
    media_assets: [],
    media_debug_full: [],
    media_pipeline_status: safeText(input.media_pipeline_status, 'skipped_non_final_success'),
    media_debug_phase: 'finalized',
    media_finished_at: finishedAt,
    media_elapsed_seconds: computeElapsedSeconds(input.media_started_at, finishedAt),
    media_stats: {
      scene_count: baseScenes.length,
      visual_mode: visualMode,
      visual_generated_count: 0,
      image_generated_count: 0,
      video_generated_count: 0,
      tts_generated_count: 0,
      failed_count: 0,
      skipped_count: baseScenes.length,
    },
  };
}

function itemSceneId(item) {
  return safeText(item?.scene_id, safeText(item?.chunk_key));
}

const visualBySceneId = new Map();
for (const item of visualItems) {
  const sceneId = itemSceneId(item);
  if (!sceneId) continue;
  visualBySceneId.set(sceneId, item);
}

const ttsBySceneId = new Map();
for (const item of ttsItems) {
  const sceneId = itemSceneId(item);
  if (!sceneId) continue;
  ttsBySceneId.set(sceneId, item);
}

const runVisual = input.media_run_image === true;
const runTts = input.media_run_tts === true;

const merged = baseScenes.map((scene) => {
  const visual = visualBySceneId.get(scene.scene_id) ?? {};
  const tts = ttsBySceneId.get(scene.scene_id) ?? {};

  const visualStatus = safeText(
    visual.video_status,
    safeText(visual.image_status, runVisual ? 'failed' : 'skipped_not_requested'),
  );
  const ttsStatus = safeText(tts.tts_status, runTts ? 'failed' : 'skipped_not_requested');

  const visualUrl = safeText(
    visual.video_url,
    safeText(
      visual.image_url,
      safeText(
        visual.video_drive_url,
        safeText(
          visual.image_drive_url,
          safeText(visual.video, safeText(visual.image)),
        ),
      ),
    ),
  );
  const voiceUrl = safeText(tts.voice_url, safeText(tts.voice_drive_url, safeText(tts.voice)));

  const durationSeconds = asDuration(
    tts.duration_seconds,
    asDuration(
      tts.duration,
      asDuration(visual.duration_seconds, asDuration(scene.estimated_duration_sec, 0)),
    ),
  );

