function asDuration(value, fallback = 0) {
  const number = Number(value);
  if (!Number.isFinite(number) || number <= 0) {
    return fallback;
  }
  return Math.round(number * 1000) / 1000;
}

function clamp(number, min, max) {
  return Math.min(max, Math.max(min, number));
}

function normalizeShotPrompts(rawList) {
  if (!Array.isArray(rawList)) return [];
  return rawList
    .map((item) => safeText(item))
    .filter(Boolean)
    .slice(0, 20);
}

function splitNarrationShots(text, targetCount) {
  const normalized = safeText(text).replace(/\r\n/g, '\n');
  if (!normalized) return [];

  const sentences = normalized
    .split(/(?<=[.!?…])\s+/)
    .map((part) => part.trim())
    .filter(Boolean);

  if (sentences.length === 0) return [];

  const count = Math.max(1, Math.min(targetCount, 20));
  const prompts = [];
  for (let i = 0; i < count; i += 1) {
    const sentence = sentences[i % sentences.length];
    prompts.push(sentence);
  }

  return prompts;
}

function buildShotPrompts(videoPromptEn, narrationText, shotCount) {
  const basePrompt = safeText(videoPromptEn, 'cinematic storytelling shot, dynamic camera, clean composition');
  const narrationShots = splitNarrationShots(narrationText, shotCount);
  const prompts = [];

  for (let i = 0; i < shotCount; i += 1) {
    const detail = safeText(narrationShots[i], safeText(narrationShots[narrationShots.length - 1]));
    const prefix = 'Shot ' + String(i + 1).padStart(2, '0') + ': ';
    if (detail) {
      prompts.push(prefix + basePrompt + '. Context: ' + detail);
    } else {
      prompts.push(prefix + basePrompt + '.');
    }
  }

  return prompts;
}

