const OPENAI_DEFAULT_MODEL = 'cx/gpt-5.4';

function normalizeModelName(rawValue, defaultValue = OPENAI_DEFAULT_MODEL) {
  const fallback = String(defaultValue ?? '').trim() || OPENAI_DEFAULT_MODEL;
  const raw = String(rawValue ?? '').trim();
  if (!raw) {
    return fallback;
  }

  const lowerRaw = raw.toLowerCase();
  if (lowerRaw === 'gpt-5') {
    return OPENAI_DEFAULT_MODEL;
  }

  if (/^cx\//i.test(raw) || /^gemini-/i.test(raw) || /^nano-banana/i.test(raw)) {
    return raw;
  }

  if (/^gpt-[a-z0-9.\-]+$/i.test(raw)) {
    return 'cx/' + raw;
  }

  return raw;
}

function asNumber(value, fallback = 0) {
  if (value === null || value === undefined) {
    return fallback;
  }
  const raw = typeof value === 'string' ? value.trim() : String(value);
  if (raw === '') {
    return fallback;
  }
  const num = Number(raw);
  return Number.isFinite(num) ? num : fallback;
}

function clampScore(value, fallback = 6) {
  if (value === null || value === undefined) return fallback;
  const raw = typeof value === 'string' ? value.trim() : String(value);
  if (raw === '') return fallback;
  const num = Number(raw);
  if (!Number.isFinite(num)) return fallback;
  if (num < 0) return 0;
  if (num > 10) return 10;
  return Math.round(num * 10) / 10;
}

function normalizeRisk(value) {
  const risk = String(value ?? '').trim().toLowerCase();
  if (risk === 'low' || risk === 'med' || risk === 'high') return risk;
  return 'med';
}

function normalizeList(value) {
  if (Array.isArray(value)) {
    return value.map((item) => String(item ?? '').trim()).filter(Boolean);
  }
  return String(value ?? '')
    .split(/[\n,]+/)
    .map((item) => item.trim())
    .filter(Boolean);
}

function normalizeFeedback(value, fallback = '') {
  const raw = String(value ?? '').replace(/\s+/g, ' ').trim();
  const text = raw || String(fallback ?? '').replace(/\s+/g, ' ').trim();
  if (!text) return '';

  const words = text.split(/\s+/).filter(Boolean);
  if (words.length <= 200) {
    return text;
  }
  return words.slice(0, 200).join(' ');
}

function normalizeForGenericMatch(value) {
  return String(value ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^\w\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
}

function isGenericQcFeedback(value) {
  const normalized = normalizeForGenericMatch(value);
  if (!normalized) return true;
  return (
    normalized === 'chua co feedback qc' ||
    normalized.includes('chua co feedback qc') ||
    normalized.includes('khong co feedback qc') ||
    normalized.includes('no qc feedback')
  );
}

function hasNonEmptyNumber(value) {
  if (value === null || value === undefined) return false;
  const raw = typeof value === 'string' ? value.trim() : String(value);
  if (raw === '') return false;
  return Number.isFinite(Number(raw));
}

function buildScoreWarnings(scores, threshold) {
  const map = {
    Hook: scores.hook_score,
    Clarity: scores.clarity_score,
    Originality: scores.originality_score,
    'Practical value': scores.practical_value_score,
  };

  return Object.entries(map)
    .filter(([, score]) => Number(score) < threshold)
    .map(([label, score]) => label + ' score=' + score + ' < ' + threshold);
}

function parseJsonObject(rawText) {
  const raw = String(rawText ?? '').trim();
  if (!raw) return null;

  try {
    return JSON.parse(raw);
  } catch (_) {}

  const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fence) {
    try {
      return JSON.parse(fence[1]);
    } catch (_) {}
  }

  const first = raw.indexOf('{');
  const last = raw.lastIndexOf('}');
  if (first >= 0 && last > first) {
    try {
      return JSON.parse(raw.slice(first, last + 1));
    } catch (_) {}
  }

  return null;
}

function stripControlTags(text) {
  const normalized = String(text ?? '').replace(/\r\n/g, '\n').trim();
  return normalized.replace(/(?:\n|^)\s*-\s*(CONTINUE|END)\s*-\s*$/i, '').trim();
}

function normalizeReviewForDisplay(reviewText) {
  const normalized = stripControlTags(reviewText);
  const sectionRegex = /<<<SECTION\|([^|\n>]+)(?:\|([^\n>]+))?>>>\s*([\s\S]*?)\s*<<<END_SECTION>>>/g;
  const blocks = [];
  let match;

  while ((match = sectionRegex.exec(normalized)) !== null) {
    const title = safeText(match[2]);
    const content = safeText(match[3]);
    if (!content) continue;
    blocks.push(title ? (title + '\n' + content) : content);
  }

  if (blocks.length > 0) {
    return blocks.join('\n\n').trim();
  }

  return normalized
    .replace(/<<<SECTION\|[^>]+>>>/g, '')
    .replace(/<<<END_SECTION>>>/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

