  return hasScalar || hasList || hasScoresObject;
}

function buildHeuristicFeedback(context) {
  const review = safeText(normalizeReviewForDisplay(context.full_review));
  const hints = [];

  if (review.length > 5000) {
    hints.push('Rut gon 10-20% de nhip doc gon hon, uu tien cau ngan va dong tu manh.');
  }
  if (/phan\\s*\\d+|bai\\s*hoc\\s*\\d+|muc\\s*\\d+/i.test(review)) {
    hints.push('Bo kieu danh so meta (Phan 1/Bai hoc 1), chuyen sang dong ke tu su lien mach.');
  }
  if (!/[\"“”']/.test(review)) {
    hints.push('Them 1-2 trich dan ngan (co nguon ro) de tang do tin cay va cam xuc.');
  }
  if (!/(vi\\s*du|chuyen\\s*that|tinh\\s*huong|doi\\s*song)/i.test(review)) {
    hints.push('Bo sung vi du doi song cu the de tang practical value.');
  }

  if (hints.length === 0) {
    hints.push('Mo bai bang 1 noi dau cu the, giu giong ke chuyen nguoi that, va ket bai bang 1 hanh dong nho co the lam ngay.');
  }

  return normalizeFeedback(hints.join(' '), 'Can them feedback QC cu the.');
}

function normalizeQcPayload(source, options = {}) {
  const raw = source && typeof source === 'object' ? source : {};
  const qcIssues = normalizeList(raw.qc_issues ?? raw.issues);
  const qcChecks = Array.isArray(raw.qc_checks) ? raw.qc_checks : [];

  const hookRaw = raw.hook ?? raw.hook_score ?? raw.scores?.hook;
  const clarityRaw = raw.clarity ?? raw.clarity_score ?? raw.scores?.clarity;
  const originalityRaw = raw.originality ?? raw.originality_score ?? raw.scores?.originality;
  const practicalRaw = raw.practical ?? raw.practical_value_score ?? raw.scores?.practical ?? raw.scores?.practical_value;
  const riskRaw = raw.risk ?? raw.risk_level;

  const derivedIssues = qcIssues.length > 0
    ? qcIssues
    : qcChecks
        .filter((check) => String(check?.status ?? '').toLowerCase() !== 'pass')
        .map((check) => String(check?.note ?? '').trim())
        .filter(Boolean);

  const feedbackFallback = safeText(options.fallbackFeedback, derivedIssues.slice(0, 3).join('; '));
  const qc = {
    qc_checks: qcChecks,
    qc_issues: derivedIssues,
    feedback: normalizeFeedback(raw.feedback, feedbackFallback || 'Can them feedback QC cu the.'),
    hook_score: clampScore(hookRaw, 6),
    clarity_score: clampScore(clarityRaw, 6),
    originality_score: clampScore(originalityRaw, 6),
    practical_value_score: clampScore(practicalRaw, 6),
    risk_level: normalizeRisk(riskRaw),
    score_warnings: [],
    qc_status: safeText(options.qcStatus, 'generated'),
    qc_error: safeText(options.qcError) || null,
  };

  qc.score_warnings = buildScoreWarnings(qc, qcScoreWarningThreshold);
  return qc;
}

function enforceQcQuality(normalizedQc, fallbackFeedback, fallbackErrorCode) {
  const qc = normalizedQc && typeof normalizedQc === 'object' ? normalizedQc : {};
  const safeFallbackFeedback = normalizeFeedback(fallbackFeedback, 'Can them feedback QC cu the.');

  const scoresAreDefault =
    Number(qc.hook_score) === 6 &&
    Number(qc.clarity_score) === 6 &&
    Number(qc.originality_score) === 6 &&
    Number(qc.practical_value_score) === 6;

  const feedbackText = safeText(qc.feedback);
  const feedbackWordCount = feedbackText.split(/\s+/).filter(Boolean).length;
  const feedbackLooksGeneric = isGenericQcFeedback(feedbackText);
  const feedbackTooShort = feedbackWordCount < 8;

  if (feedbackLooksGeneric || (scoresAreDefault && feedbackTooShort)) {
    const existingIssues = Array.isArray(qc.qc_issues) ? qc.qc_issues : [];
    const nextIssues = existingIssues.length > 0 ? existingIssues : ['QC fallback.'];
    return {
      ...qc,
      qc_issues: nextIssues,
      feedback: safeFallbackFeedback,
      qc_status: 'fallback',
      qc_error: safeText(qc.qc_error, fallbackErrorCode),
      score_warnings: buildScoreWarnings({
        hook_score: qc.hook_score,
        clarity_score: qc.clarity_score,
        originality_score: qc.originality_score,
        practical_value_score: qc.practical_value_score,
      }, qcScoreWarningThreshold),
    };
  }

  return qc;
}

async function resolveQcPayload() {
  const existingQc = input.qc && typeof input.qc === 'object'
    ? input.qc
    : {
        hook_score: input.hook_score,
        clarity_score: input.clarity_score,
        originality_score: input.originality_score,
        practical_value_score: input.practical_value_score,
        risk_level: input.risk_level,
        feedback: input.feedback,
        score_warnings: input.score_warnings,
        qc_status: input.qc_status,
      };

  const hasExistingScores =
    hasNonEmptyNumber(existingQc?.hook_score) &&
    hasNonEmptyNumber(existingQc?.clarity_score) &&
    hasNonEmptyNumber(existingQc?.originality_score) &&
    hasNonEmptyNumber(existingQc?.practical_value_score);

  const heuristicFeedback = buildHeuristicFeedback(input);

  if (hasExistingScores) {
    const normalizedExisting = normalizeQcPayload(existingQc, {
      qcStatus: safeText(existingQc?.qc_status, 'generated'),
      qcError: safeText(existingQc?.qc_error),
      fallbackFeedback: heuristicFeedback,
    });
    return enforceQcQuality(normalizedExisting, heuristicFeedback, 'qc_existing_payload_generic');
  }

  const fallbackQc = {
    qc_checks: [],
    qc_issues: ['QC fallback.'],
    feedback: heuristicFeedback,
    hook_score: 6,
    clarity_score: 6,
    originality_score: 6,
    practical_value_score: 6,
    risk_level: 'med',
    score_warnings: [],
    qc_status: 'fallback',
    qc_error: null,
  };

  try {
    const promptPayload = {
      task: 'QC a Vietnamese long-form book review script.',
      policy: {
        quote_policy: 'Only accept direct quote if source certainty is high. Otherwise mark warn.',
        no_rewrite: true,
      },
      input: {
        request: safeText(input.user_input),
        intro_excerpt: safeText(input.review_intro),
        outro_excerpt: safeText(input.review_outro),
        review_excerpt: safeText(normalizeReviewForDisplay(input.full_review)),
        review_readable: safeText(input.review_readable, safeText(normalizeReviewForDisplay(input.full_review))),
        review_manifest: input.review_manifest && typeof input.review_manifest === 'object' ? input.review_manifest : null,
      },
      required_json_schema: {
        hook: 0,
        clarity: 0,
        originality: 0,
        practical: 0,
        risk: 'low|med|high',
        feedback: 'string (Vietnamese, actionable, <= 200 words)',
        qc_issues: ['string (optional)'],
      },
    };

    const baseMessages = [
      {
        role: 'system',
        content: qcPromptTemplate,
      },
      {
        role: 'user',
        content: JSON.stringify(promptPayload),
      },
    ];

    const response = await callOpenAI(baseMessages, { useJsonObject: true });

    const content = String(response?.choices?.[0]?.message?.content ?? '').trim();
    let parsed = parseJsonObject(content);
    if (!parsed || typeof parsed !== 'object' || !hasUsableQcObject(parsed)) {
      const retryPromptPayload = {
        ...promptPayload,
        output_rule: 'Tra ve JSON day du key hook,clarity,originality,practical,risk,feedback,qc_issues; feedback bat buoc khong rong.',
      };
      const retryResponse = await callOpenAI([
        {
          role: 'system',
          content: qcPromptTemplate,
        },
        {
          role: 'user',
          content: JSON.stringify(retryPromptPayload),
        },
      ], { useJsonObject: false });

      const retryContent = String(retryResponse?.choices?.[0]?.message?.content ?? '').trim();
      const retryParsed = parseJsonObject(retryContent);
      if (!retryParsed || typeof retryParsed !== 'object' || !hasUsableQcObject(retryParsed)) {
        throw new Error('QC response missing required fields.');
      }
      parsed = retryParsed;
    }

    const normalized = normalizeQcPayload(parsed, {
      qcStatus: 'generated',
      fallbackFeedback: heuristicFeedback,
    });
    return enforceQcQuality(normalized, heuristicFeedback, 'qc_payload_empty_feedback');
  } catch (error) {
    fallbackQc.qc_error = safeText(error?.message, String(error));
    fallbackQc.score_warnings = buildScoreWarnings(fallbackQc, qcScoreWarningThreshold);
    return fallbackQc;
  }
}

