function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function asNumber(value, fallback = 0) {
  const number = Number(value);
  return Number.isFinite(number) ? number : fallback;
}

function safeJsonParse(value, fallback) {
  try {
    return JSON.parse(String(value ?? ''));
  } catch (_) {
    return fallback;
  }
}

function safeJsonStringify(value, fallback = '{}') {
  try {
    return JSON.stringify(value);
  } catch (_) {
    return fallback;
  }
}

function nowIso() {
  return new Date().toISOString();
}

function normalizeDriveContext(source) {
  const obj = source && typeof source === 'object' ? source : {};
  return {
    session_folder_id: safeText(obj.session_folder_id),
    session_folder_url: safeText(obj.session_folder_url),
    session_voice_folder_id: safeText(obj.session_voice_folder_id),
    session_voice_folder_url: safeText(obj.session_voice_folder_url),
    session_image_folder_id: safeText(obj.session_image_folder_id, safeText(obj.session_video_folder_id)),
    session_image_folder_url: safeText(obj.session_image_folder_url, safeText(obj.session_video_folder_url)),
    session_video_folder_id: safeText(obj.session_video_folder_id, safeText(obj.session_image_folder_id)),
    session_video_folder_url: safeText(obj.session_video_folder_url, safeText(obj.session_image_folder_url)),
    session_review_file_id: safeText(obj.session_review_file_id),
    session_review_file_url: safeText(obj.session_review_file_url),
    session_metadata_file_id: safeText(obj.session_metadata_file_id),
    session_metadata_file_url: safeText(obj.session_metadata_file_url),
    session_manifest_file_id: safeText(obj.session_manifest_file_id),
    session_manifest_file_url: safeText(obj.session_manifest_file_url),
    session_sheet_id: safeText(obj.session_sheet_id),
    session_sheet_url: safeText(obj.session_sheet_url),
  };
}

function mergeDriveContext(baseContext, incomingContext) {
  const base = normalizeDriveContext(baseContext);
  const incoming = normalizeDriveContext(incomingContext);
  const merged = { ...base };

  for (const [key, value] of Object.entries(incoming)) {
    if (safeText(value)) {
      merged[key] = safeText(value);
    }
  }

  return merged;
}

const n8nApiUrl = safeText(input.n8n_api_url).replace(/\/$/, '');
const n8nApiKey = safeText(input.n8n_api_key);
const sessionStoreName = safeText(input.session_store_name, 'book_review_sessions');
const sessionToken = safeText(input.session_token);

if (!sessionToken || !n8nApiUrl || !n8nApiKey || typeof requestHelper !== 'function') {
  return {
    ...input,
    session_context_persist_status: 'skipped_missing_config',
    session_context_persist_error: null,
  };
}

async function apiRequest(method, path, options = {}) {
  return await requestHelper({
    method,
    url: n8nApiUrl + path,
    headers: {
      'X-N8N-API-KEY': n8nApiKey,
    },
    qs: options.qs,
    body: options.body,
    json: true,
    timeout: 60000,
  });
}

try {
  const list = await apiRequest('GET', '/api/v1/data-tables', {
    qs: { limit: 200 },
  });

  const tables = Array.isArray(list?.data) ? list.data : [];
  const table = tables.find((item) => String(item?.name ?? '') === sessionStoreName);
  const tableId = safeText(table?.id);

  if (!tableId) {
    return {
      ...input,
      session_context_persist_status: 'skipped_missing_table',
      session_context_persist_error: null,
    };
  }

  const rows = await apiRequest('GET', '/api/v1/data-tables/' + tableId + '/rows', {
    qs: {
      limit: 1,
      sortBy: 'updated_at:desc',
      filter: JSON.stringify({
        type: 'and',
        filters: [
          {
            columnName: 'session_token',
            condition: 'eq',
            value: sessionToken,
          },
        ],
      }),
    },
  });

  const existingRow = Array.isArray(rows?.data) ? (rows.data[0] ?? {}) : {};
  const payload = safeJsonParse(existingRow.payload_json, {}) ?? {};

  const metadataFromRow = safeJsonParse(existingRow.metadata_json, null);
  const metadata = input.metadata && typeof input.metadata === 'object'
    ? input.metadata
    : (metadataFromRow && typeof metadataFromRow === 'object'
      ? metadataFromRow
      : (payload.metadata && typeof payload.metadata === 'object' ? payload.metadata : {}));

  const commands = Array.isArray(input.reviewer_commands)
    ? input.reviewer_commands.slice(-200)
    : Array.isArray(payload.commands)
      ? payload.commands.slice(-200)
      : [];

  const mergedDrive = mergeDriveContext(
    mergeDriveContext(payload.drive_context, payload),
    input,
  );

  const reviewReadable = safeText(
    input.review_readable,
    safeText(input.full_review, safeText(payload.review_readable, safeText(existingRow.full_review, safeText(payload.full_review)))),
  );

  const reviewManifest = input.review_manifest && typeof input.review_manifest === 'object'
    ? input.review_manifest
    : (payload.review_manifest && typeof payload.review_manifest === 'object' ? payload.review_manifest : null);

  const updatedAt = nowIso();
  const stage = safeText(input.reviewer_stage, safeText(existingRow.stage, safeText(payload.stage, 'media_pending')));
  const stopReason = safeText(input.stop_reason, safeText(existingRow.stop_reason, safeText(payload.stop_reason)));
  const awaitingInstruction =
    safeText(existingRow.awaiting_instruction, payload.awaiting_instruction === true ? '1' : '');

  const nextPayload = {
    ...payload,
    session_token: sessionToken,
    stage,
    stop_reason: stopReason,
    updated_at: updatedAt,
    user_input: safeText(input.user_input, safeText(existingRow.user_input, safeText(payload.user_input))),
    full_review: reviewReadable,
    review_readable: reviewReadable,
    review_manifest: reviewManifest,
    review_intro: safeText(input.review_intro, safeText(existingRow.review_intro, safeText(payload.review_intro))),
    review_outro: safeText(input.review_outro, safeText(existingRow.review_outro, safeText(payload.review_outro))),
    metadata,
    commands,
    drive_context: mergedDrive,
    ...mergedDrive,
  };

  const rowData = {
    session_token: sessionToken,
    stage,
    deadline_at: safeText(existingRow.deadline_at, safeText(payload.deadline_at)),
    awaiting_instruction: awaitingInstruction,
    user_input: safeText(nextPayload.user_input),
    full_review: reviewReadable,
    review_intro: safeText(nextPayload.review_intro),
    review_outro: safeText(nextPayload.review_outro),
    qc_json: safeText(existingRow.qc_json, safeJsonStringify(payload.qc ?? {}, '{}')),
    metadata_json: safeJsonStringify(metadata, '{}'),
    review_round: asNumber(existingRow.review_round, asNumber(payload.review_round, 0)),
    metadata_round: asNumber(existingRow.metadata_round, asNumber(payload.metadata_round, 0)),
    commands_json: safeJsonStringify(commands, '[]'),
    stop_reason: stopReason,
    updated_at: updatedAt,
    payload_json: safeJsonStringify(nextPayload, '{}'),
  };

  await apiRequest('POST', '/api/v1/data-tables/' + tableId + '/rows/upsert', {
    body: {
      filter: {
        type: 'and',
        filters: [
          {
            columnName: 'session_token',
            condition: 'eq',
            value: sessionToken,
          },
        ],
      },
      data: rowData,
      returnData: false,
    },
  });

  return {
    ...input,
    ...mergedDrive,
    review_readable: reviewReadable,
    review_manifest: reviewManifest,
    session_context_persist_status: 'success',
    session_context_persist_error: null,
  };
} catch (error) {
  return {
    ...input,
    session_context_persist_status: 'failed',
    session_context_persist_error: safeText(error?.message, String(error)).slice(0, 400) || 'persist_failed',
  };
}

